import { NodeList, System, Engine, Entity } from '../core';
import { jiboRef } from '../../jibo';
import { FetchAssetNode } from '../nodes';
import { FetchAsset, RequestCommand, AssetCache } from '../components';
import {ResponseCode, FetchAssetEvents, FetchAssetErrorDetails} from 'jibo-command-protocol';
import os =require('os');

export const MIN_FREE_MEM_RATE = 0.05;

export default class LoadAssetSystem extends System
{
    private nodes:NodeList<FetchAssetNode>;
    private engine:Engine;

    constructor()
    {
        super();
    }

    public addToEngine( engine:Engine ):void
    {
        this.engine = engine;
        this.nodes = this.engine.getNodeList( FetchAssetNode );

        for( let node:FetchAssetNode = this.nodes.head; node; node = node.next )
        {
            this.onAdded( node );
        }
        this.nodes.nodeAdded.add( this.onAdded );
        this.nodes.nodeRemoved.add( this.onRemoved );
    }

    public update( time:number ):void
    {
        let node:FetchAssetNode = this.nodes.head;
        for (node; node; node = node.next)
        {
            let fetchAsset:FetchAsset = node.fetchAsset;
            let request:RequestCommand = node.request;
            if (!request.acknowledged) {
              //check memory
              if (!this.thereIsFreeMemory())
              {
                let code: JIBO.v1.ResponseCodes.ResponseCodeType = ResponseCode.NotAcceptable;
                request.setAcknowledge(code, true, FetchAssetErrorDetails.OutOfMemory);
              }else {
                  let assetToken = jiboRef.jibo.loader.load(this.buildAsset(fetchAsset),(err,res)=>{
                      let response: JIBO.v1.FetchAssetEvent;
                      if (err)
                      {
                          response = {
                              Event: FetchAssetEvents.AssetFailed,
                              Detail: err
                          };
                      }else {
                          response = {
                              Event: FetchAssetEvents.AssetReady,
                              Detail: fetchAsset.name
                          };
                      }
                      request.addResponse(response,true);
                  });
                  node.assetCache.assetTokens.set(fetchAsset.name, assetToken);
              }
            }
        }
    }

    public removeFromEngine( engine:Engine ):void
    {
        let entityCache:Entity = engine.getEntityByName("assetCache");
        if (entityCache){
            let assetCache: AssetCache = entityCache.get(AssetCache);
            let removeAssetToken = (value,key,map)=> {
                jiboRef.jibo.loader.unload(value);
                map.delete(key);
            };
            assetCache.assetTokens.forEach(removeAssetToken);
        }
        this.nodes = null;
    }

    private thereIsFreeMemory():boolean
    {
        // only check memory if we're on robot
        if(jiboRef.jibo.runMode === jiboRef.jibo.RunMode.ON_ROBOT) {
            return (os.freemem()/os.totalmem() > MIN_FREE_MEM_RATE);
        }
        return true;
    }

    private buildAsset(fetchAsset: FetchAsset): any {
        if (fetchAsset.uri.endsWith(".wav") || fetchAsset.uri.endsWith(".mp3")) {
            return {
                id: fetchAsset.name,
                src: fetchAsset.uri,
                type: "sound",
                block: false, // allow only playing at once
                volume: 1, // from 0 to 1
                panning: 0, // from -1 (left) to 1 (right)
                loop: false, // allow looping
                autoPlay: false, // play when finished
                cache: jiboRef.jibo.loader.activeCache,
                complete: function(err, sound){ /* no opt */ } // returns jibo.sound.Sound object
            };
        }else if (fetchAsset.uri.endsWith(".png") || fetchAsset.uri.endsWith(".jpg") || fetchAsset.uri.endsWith(".jpeg")){
            return {
                id: fetchAsset.name,
                src: fetchAsset.uri,
                type: "texture", // required
                upload: false, // upload to GPU when finished downloading
                cache: jiboRef.jibo.loader.activeCache,
                complete: function(err, texture){ /* no opt */ } // returns PIXI.Texture object
            };
        }else {
            return null;
        }
    }

    private onAdded = ( node:FetchAssetNode ) => {
        // TODO :: Could use better logic here
    }

    private onRemoved = ( node:FetchAssetNode ) => {
        // @TODO: does it need some handling?
    }
}
