import { Signal1 } from '../signals/Signal1';
import { ITickProvider } from './ITickProvider';

export default class JiboTickProvider extends Signal1<number> implements ITickProvider
{
    public playing:boolean;
    private _rafId:number;
    private _previousTime:number;
    private _minTimeDiff:number;

    private DESIRED_FREQ:number = 20; //Measured in Hertz

    constructor()
    {
        super();
    }

    public start():void
    {
        this._previousTime = performance.now();
        this.playing = true;
        this._rafId = requestAnimationFrame( this.update );
        this._minTimeDiff = 1 / this.DESIRED_FREQ * 1000;
    }

    public stop():void
    {
        cancelAnimationFrame( this._rafId );
    }

    private update = () => {
        this._rafId = requestAnimationFrame( this.update );
        let time = performance.now();

        let timeDiff = (time - this._previousTime); //Time difference in ms
        if (timeDiff > this._minTimeDiff) {
            this.dispatch( (time - this._previousTime) / 1000 );
            this._previousTime = time;
        }
    }
}
