import { NodeList, System, Engine } from '../core';
import { jiboRef } from '../../jibo';
import { PlayNode } from '../nodes';
import { Play, RequestCommand } from '../components';
import { AsyncCommandEvent, ResponseCode } from 'jibo-command-protocol';
import { Parser } from 'jibo-node-xml';

export default class PlaySystem extends System
{
    private nodes:NodeList<PlayNode>;
    private engine:Engine;

    constructor()
    {
        super();
    }

    public addToEngine( engine:Engine ):void
    {
        this.engine = engine;
        this.nodes = this.engine.getNodeList( PlayNode );

        // TODO :: there can only be one active Look At, block others
        for( let node:PlayNode = this.nodes.head; node; node = node.next )
        {
            this.onAdded( node );
        }
        this.nodes.nodeAdded.add( this.onAdded );
        this.nodes.nodeRemoved.add( this.onRemoved );
    }

    public update( time:number ):void
    {
        let node:PlayNode = this.nodes.head;
        // A new the jibo.embodied.speech.speak interrupts the previous one.
        // The previous node response is sent when the promise is resolved.
        // A new jibo.sound.play won't interrupt the previous one. This is
        // the behaviour that we want.
        for (node; node; node = node.next)
        {
            let play:Play = node.play;
            if (!play.activated){
                if (play.textInESML) {
                    play.activated = true;
                    play.audioId = this.getAudioFile(play.textInESML);
                    let request:RequestCommand = node.request;
                    this.playESML(play).then((response) => {
                        play.completed = true;
                        request.addResponse(response, true);
                    });
                }
                else {
                    // Play command must have ESML specified, this error shouldn't get this far, but we check anyway
                    let code: JIBO.v1.ResponseCodes.ResponseCodeType;
                    code = ResponseCode.BadRequest;
                    node.request.setAcknowledge(code,true);
                }
            }
        }
    }

    public removeFromEngine( engine:Engine ):void
    {
        this.nodes = null;
    }

    private getAudioFile(esml:string): string
    {
      let esmlParsed = Parser.parseXML(esml);
      let allNodes = esmlParsed.gatherChildren();
      if (allNodes.length === 1)
      {
          let tagNode = esmlParsed.findFirstChildType('audio');
          if (tagNode)
          {
              let path = tagNode.getAttribute('path');
              if (path)
              {
                  return String(path);
              }
          }
      }
      return null;
    }

    private playESML(play:Play): Promise<any>
    {
        return new Promise((resolve) => {
            let jibo = jiboRef.jibo;
            // play audio only
            if (play.audioId) {
                if (jibo.sound.exists(play.audioId)) {
                    jibo.sound.play(play.audioId, () =>
                    {
                        let response: JIBO.v1.AsyncStatusEvent =
                        {
                            Event: AsyncCommandEvent.Stop
                        };
                        resolve(response);
                    });
                }
                else {
                    let response: JIBO.v1.AsyncErrorEvent =
                    {
                        Event: AsyncCommandEvent.Error,
                        EventError: {
                            ErrorString: "No sound matching alias '" + play.audioId +"'",
                            ErrorCode: 2
                        }
                    };
                    resolve(response);
                }
            }
            // play standard ESML
            else {
                jibo.embodied.speech.speak(play.textInESML, play.speakOptions, play.autoRuleConfig)
                .then(() => {
                    let response: JIBO.v1.AsyncStatusEvent =
                    {
                        Event: AsyncCommandEvent.Stop
                    };
                    resolve(response);
                })
                .catch((err) => {
                    let response: JIBO.v1.AsyncErrorEvent = {
                        Event: AsyncCommandEvent.Error,
                        EventError: {
                            ErrorString: err.message ? err.message : String(err),
                            ErrorCode: 1
                        }
                    };
                    resolve(response);
                });
            }
        });
    }

    private onAdded = ( node:PlayNode ) => {
        // TODO :: Could use better logic here
    }

    private onRemoved = ( node:PlayNode ) => {
        // if the node is being removed, but was not interrupted by another Play command then we need to clean it up
        if (node.play.activated && !node.play.completed) {
            // TODO :: This isn't a clean may to manage this
            if (jiboRef.jibo.embodied.speech.isActive()) {
                jiboRef.jibo.embodied.speech.stop()
                .then(() => {
                    //@TODO: test if the speak promise is solved when stopped
                });
            }

            if(node.play.audioId) {
                jiboRef.jibo.sound.stop(node.play.audioId);
            }
        }
    }
}
