import { Engine, NodeList, System } from '../core';
import { SessionNode } from '../nodes';
import { Session, RequestCommand } from '../components';
import { DisconnectCode, ResponseCode } from 'jibo-command-protocol';
import { jiboRef } from '../../jibo';

export default class SessionSystem extends System
{
    private nodes:NodeList<SessionNode>;

    constructor()
    {
        super();
    }

    public addToEngine( engine:Engine ):void
    {
        this.nodes = engine.getNodeList( SessionNode );
        this.nodes.nodeRemoved.add( this.onRemoved );
    }

    public removeFromEngine( engine:Engine ):void
    {
        this.nodes = null;
    }

    public update( time:number ):void
    {
        let node:SessionNode = this.nodes.head;
        for( node; node; node = node.next )
        {
            if(node.next)
            {
                node.request.setAcknowledge(ResponseCode.Conflict, true);
            }
            else {
                const session:Session = node.session;
                const request:RequestCommand = node.request;
                if (request.acknowledged) {

                    if(session.waitingOnReconnect) {
                        // waiting on reconnect
                        session.reconnectDuration += time;
                        if(session.reconnectDuration > session.reconnectTimeout) {
                            // session should timeout
                            session.endSessionMethod(DisconnectCode.ReconnectTimeout);
                            // remove session entity
                            request.setComplete();
                        }
                    }
                    else{
                        // update session time out basedon inactivity
                        session.inactivityDuration += time;
                        if(session.inactivityDuration > session.inactivityTimeout) {
                            // session should timeout
                            session.hasConnection = false;
                            session.endSessionMethod(DisconnectCode.InactivityTimeout);
                            // remove session entity
                            request.setComplete();
                        }
                    }
                }
                else{
                    // NOTE :: the session id should be set by the SessionManager on new session creation
                    const body:JIBO.v1.SessionInfo = {
                        SessionID: session.id,
                        Version: request.version
                    };
                    request.setAcknowledge(ResponseCode.OK, false, body);
                    if(node.session.headTouchStopTime) {
                        jiboRef.jibo.action.setHoldHeadToQuitDuration(node.session.headTouchStopTime);
                    }
                }
            }
        }
    }

    private onRemoved = ( node:SessionNode ) => {
        // clean up Session component
        node.session.storedEvents = null;
        node.session.sendMethod = null;
        node.session.endSessionMethod = null;
        jiboRef.jibo.action.resetHoldToQuitTime();
    }
}
