import { NodeList, System, Engine } from '../core';
import { jiboRef } from '../../jibo';
import { HotWordNode } from '../nodes';
import { RequestCommand, HotWord, LightRing } from '../components';
import CommandUtil from '../../CommandUtil';
import { AsyncCommandEvent, EntityType, HotWordEvents, ResponseCode} from 'jibo-command-protocol';
// Only importing type definition - do not use for runtime things
import JiboType = require('../../../../jibo');

export default class HotWordSystem extends System
{
    private nodes:NodeList<HotWordNode>;
    private hjEnable:boolean;
    private hjHeard:boolean = false;
    private speaker:JIBO.v1.Speaker;
    private hjToken:JiboType.jetstream.HotwordModeToken;

    constructor(enable:boolean = true) {
        super();
        this.hjEnable = enable;
        this.onHJHeard = this.onHJHeard.bind(this);
    }

    public addToEngine( engine:Engine ):void {
        // determine if we should enable or disable HJ globals
        if(this.hjEnable) {
            // Assumes that global listen behavior is enabled
            // setup up system level listener for HeyJibo heard
            this.resetHJHeard();
            jiboRef.jibo.jetstream.events.hjHeard.on(this.onHJHeard);
            this.nodes = engine.getNodeList( HotWordNode );
        }

        // if HJ is disabled then system is only used to set HJ listen mode to none
        // if HJ is enabled then set mode to HJ listen only
        this.enableHJ(this.hjEnable);
    }

    public update( time:number ):void {
        if(this.nodes) {
            // dispatch event on a HJ heard and manage cool down
            let node:HotWordNode = this.nodes.head;
            for( node; node; node = node.next ){
                let request:RequestCommand = node.request;
                if(node.next) {
                    // interrupt
                    if (request.acknowledged) {
                        let response: JIBO.v1.AsyncErrorEvent = {
                            Event: AsyncCommandEvent.Error,
                            EventError: {
                                ErrorString: "HotWord Subscribe overwritten",
                                ErrorCode: 1
                            }
                        };
                        request.addResponse(response,true);
                        node.entity.remove(LightRing);
                    } else {
                        request.setAcknowledge(ResponseCode.Conflict,true);
                    }
                }
                else {
                    const hotWord:HotWord = node.hotWord;
                    if(hotWord.coolDown > 0) {
                        hotWord.coolDown -= time;
                        if(hotWord.coolDown <= 0) {
                            hotWord.coolDown = 0;
                            node.entity.remove(LightRing);
                        }
                    }
                    else if(this.hjHeard) {
                        const response: JIBO.v1.HotWordHeardEvent = {
                            Event: HotWordEvents.HotWordHeard,
                            Speaker: this.speaker
                        };
                        request.addResponse(response);
                        // set cool down
                        hotWord.coolDown = hotWord.coolDownMax;
                        
                        // add light ring component
                        const lightRing:LightRing = new LightRing();
                        // use light ring resource while in cool down
                        lightRing.setColor(CommandUtil.LISTEN_COLORS);
                        node.entity.add(lightRing);
                    }
                }
            }   
            this.resetHJHeard();
        }
    }

    // TODO :: This should really be async, need to do this for all systems
    public removeFromEngine( engine:Engine ):void {
        this.nodes = null;
        // if hj was enabled, remove listener
        if(this.hjEnable){
            jiboRef.jibo.jetstream.events.hjHeard.off(this.onHJHeard);
            
        }
        // if closed before hjHeard has been handled perform soem clean up
        this.resetHJHeard();
        // release HJ token if one was created
        if(this.hjToken) {
            this.hjToken.release().catch((err) => {
                //eat the error
            }).then(() => {
                this.hjToken = null;
            });
        }
    }

    /**
     * Disables HJ listening or allows for HJ only listening
     * TODO :: for now we do NOT support HJ with a listen, though we will want to allow this support eventually.
     * @param {boolean} enable 
     */
    private enableHJ (enable:boolean):Promise<void> {
        if(enable) {
            //set HJ mode to listen for HJ only
            if (!this.hjToken) {
                this.hjToken = jiboRef.jibo.jetstream.setHotwordMode(jiboRef.jibo.jetstream.types.HotwordListenMode.HJ_Only);
            }
            else {
                // this.hjToken is already defined, this really shouldn't happen
            }
            return this.hjToken.activated.catch((err) => {
                //eat the error
            });
        } else {
            // seyt HJ mode to disable HJ listens
            if (!this.hjToken) {
                this.hjToken = jiboRef.jibo.jetstream.setHotwordMode(jiboRef.jibo.jetstream.types.HotwordListenMode.Disabled);
            }
            else {
                // this.hjToken is already defined, this really shouldn't happen
            }
            return this.hjToken.activated.catch((err) => {
                //eat the error
            });
        }
    }

    private onHJHeard(data:any):void {
        this.hjHeard = true;
        // TODO :: This doesn't return the data required by the Protocol
        let stubSpeaker:JIBO.v1.Speaker = {
            LPSPosition: {
                Position: [0,0,0],
                AngleVector: [0,0],
                Confidence: 0
            },
            SpeakerID: {
                Type: EntityType.Unknown,
                Confidence: 0
            }
        };
        this.speaker = stubSpeaker;
    }

    private resetHJHeard():void {
        if(this.hjHeard) {
            // force embodied listen behavior to end 
            jiboRef.jibo.embodied.listen.waitForIdle(true);
            // force mim manager to stop waiting
            jiboRef.jibo.globalEvents.shared.hjOnly.emit();
        }
        this.hjHeard = false;
        this.speaker = null;
    }
}
