import { EventEmitter } from 'events';
import { Log } from 'jibo-log';
import parentLog from '../log';
import { EntityManager } from './EntityManager';
import { Entity } from './core';
import { Permissions } from '../Permissions';

export default class CommandManager extends EventEmitter {

    public log: Log;
    public entityManager: EntityManager;
    private _permissions:Permissions;

    constructor(permissions:Permissions) {
        super();
        this._permissions = permissions;
        this.log = parentLog.createChild('command-manager');
        this.init();
    }

    public init() {
        // entity management classes
        this.entityManager = new EntityManager(this._permissions);
    }

    public reset() {
        this.entityManager.reset();
        this.init();
    }

    public dispose(): void {
        this.entityManager.dispose();
        // TODO :: Will readdress this as we understand what needs to be disposed
    }

    // convert protocol into a command entity & add to engine
    public onCommand(data: JIBO.v1.Command):Entity {
        return this.entityManager.addCommand(data);
    }

    // start a command session, creates systems required for a command session and starts entity enine
    public startSession(sessionEntity:Entity):void {
        if(!this.entityManager.active) {
            this.entityManager.addSessionSystems(sessionEntity);
            this.entityManager.start();
        }
        else {
            // log stuff
            this.log.warn('startSession() called but entity engine is already active');
        }
    }
}
