import { Engine, NodeList, System } from '../core';
import { GetConfigNode } from '../nodes';
import { GetConfig, RequestCommand } from '../components';
import { jiboRef } from '../../jibo';
import * as THREE from '@jibo/three';
import {BodyState} from 'jibo-common-types';
import {ConfigEvents} from 'jibo-command-protocol';

/**
 * AttentionSystem pushes attention modes to the expression service.
 * This system works to maintain that only one mode is pushed at a time.
 * When all AttentionNodes are removed the attention mode will return the underlying mode.
 */
export default class GetConfigSystem extends System
{
    private nodes:NodeList<GetConfigNode>;

    constructor()
    {
        super();
    }

    public addToEngine( engine:Engine ):void
    {
        this.nodes = engine.getNodeList( GetConfigNode );
        this.nodes.nodeRemoved.add( this.onRemoved );
    }

    public update( time:number ):void
    {
        let node:GetConfigNode = this.nodes.head;
        for( node; node; node = node.next )
        {
            console.log("got node");
            let request:RequestCommand = node.request;
            if (!request.acknowledged) {
                let getConfig:GetConfig = node.getConfig;
                this.getConfigState(getConfig).then((response)=>{
                    request.addResponse(response,true);
                });
            }
        }
    }

    public removeFromEngine( engine:Engine ):void
    {
        this.nodes = null;
    }

    private getConfigState(getConfig:GetConfig) {
        return new Promise ((resolve, reject) => {
            let config: JIBO.v1.ConfigEvent ;
            let bs:BodyState = new BodyState();
            let battery:JIBO.v1.BatteryType = {
                Settable: false,
                Capacity: bs.powerState.battery.capacity,
                Max_capacity: bs.powerState.battery.max_capacity,
                Charge_rate: bs.powerState.battery.charge_rate
            };
            let wifi:JIBO.v1.WifiType = {
                Settable: false,
                Strength: 0,
            };

            let mixers:JIBO.v1.MixersType = {
                Settable: true,
                Master: null
            };

            const head = jiboRef.jibo.expression.features.head;
            let actualPosition: THREE.Vector3 = head.direction.clone().add(head.position);
            let position:JIBO.v1.PositionType = {
                WorldPosition: [actualPosition.x,actualPosition.y,actualPosition.z],
                AnglePosition: this.XYZ2Angles(actualPosition)
            };

            mixers.Master = jiboRef.jibo.volume.currentVolume  / 10;
            jiboRef.jibo.wifi.getCurrentNetwork((err,net)=>{
                wifi.Strength = net.strength;
                config = {
                    Event: ConfigEvents.onConfig,
                    Battery: battery,
                    Wifi: wifi,
                    Mixers: mixers,
                    Position:position
                };
                resolve(config);
            });
        });

    }

    private XYZ2Angles(actualPosition:THREE.Vector3): JIBO.v1.AngleVector {
        return [0,0];
    }

    private onRemoved = ( node:GetConfigNode ) => {
        /* no opt */
    }

}
