import {Event} from 'jibo-typed-events';
import { DisconnectCode } from 'jibo-command-protocol';
import CommandLibrary from './index';
import CommandProxy from './CommandProxy';

export type MessageIn = (message:JIBO.v1.Command) => void;
export type MessageOut = (message:JIBO.v1.AllResponses) => void;
export type SessionClosed = (code:JIBO.v1.DisconnectCodes.DisconnectCodeType) => void;

/**
 * Interface for 'clients' of the command library.
 * would be sent down to the comman dlibrary
 * groups (buttons, labels, .etc) Has base methods that deal with display
 * and positioning.
 *
 * @interface ICommandClient
 */
export class CommandConnector {

    public version:JIBO.v1.ProtocolVersions.ProtocolVersionType;

    // event dispatched when connection is for session to start
    public onReady:Event<void>;

    // aco for this connection
    private _aco:JIBO.v1.ACO;
    // flag to deteremine if connection is active
    private _isConnected:boolean;
    // flag to deteremine if waiting for a reconnect
    private _isAwaitingReconnect:boolean;
    // id of the session
    private _id:string;
    // flag to deteremine if connection is ready for session to start
    private _isReady:boolean;
    // Id of active session, value provided from command library once session starts
    private _sessionId:string;
    // proxy for the command library
    private _commandProxy:CommandProxy;
    // event dispatched when connect is called, listened to by commandLibrary
    private _onConnect:Event<CommandConnector>;
    // reference to callback handling response messages from command library
    private _responseCB:MessageOut;
    // reference to callback handling a session close driven by command librray
    private _sessionEndedCB:SessionClosed;

    // get unique id of the connector
    public get id():string {
        return this._id;
    }

    // get the permissions for the conector's current connection
    public get aco():JIBO.v1.ACO {
        return this._aco;
    }

    // get if the connector is ready for a session to start
    public get isReady():boolean {
        return this._isReady;
    }

    // get if the connector is currently connected to command library
    public get isConnected():boolean {
        return this._isConnected;
    }

    // get if the connector is currently waiting for a reconnection
    public get isAwaitingReconnect():boolean {
        return this._isAwaitingReconnect;
    }

    // get current session id, defined once a session has started
    public get sessionId():string {
        return this._sessionId;
    }

    // set the handler for response from command library
    public set responseHandler(handler:MessageOut) {
        this._responseCB = handler;
    }

    // set the handler for session closed
    public set sessionClosedHandler(handler:SessionClosed) {
        this._sessionEndedCB = handler;
    }

    /**
     * Constructor
     * @param {string} id identifier for the CommandConnector
     * @param {CommandLibrary} commandLib instance of the CommandLibrary, required to setup connection
     * @param {boolean} [isReady = true] flag determining if session can begin immediately,
     * if false then the owner of the CommandConnector is responsible for setting this flag
     * @private
     */
    constructor (id:string, commandLib:CommandLibrary, isReady:boolean = true) {
        // bind methods
        this.onResponse = this.onResponse.bind(this);
        this.onSessionClose = this.onSessionClose.bind(this);
        this.onSessionStarted = this.onSessionStarted.bind(this);

        this._id = id;
        this._isConnected = false;
        this._isAwaitingReconnect = false;
        this._aco = null;
        this._commandProxy = null;
        this._responseCB = null;
        this._sessionEndedCB = null;
        this._sessionId = '';
        this._isReady = isReady;
        this.onReady = new Event<void>('Conection ready, id:' + this._id);
        this._onConnect = new Event<CommandConnector>('Connect to command library');
        this._onConnect.on(commandLib.connect);
    }

    /**
     * Called by client to activate connection with command library
     * @param {ACO} aco permissions for this connection
     * @param {MessageOut} [responseCB] handler for responses coming from the CommandLibrary
     * @param {SessionClosed} [sessionEndedCB] handler for session being closed
     */
    public connect(aco:JIBO.v1.ACO, responseCB?:MessageOut, sessionEndedCB?:SessionClosed):void {
        this._aco = aco;

        // emit connection
        this._onConnect.emit(this);
        // then set handlers
        this._responseCB = responseCB;
        this._sessionEndedCB = sessionEndedCB;
        // then set flag to connected
        this._isConnected = true;
        this._isAwaitingReconnect = false;
    }

    /**
     * Called by client or command library to end connection.
     * @param {DisconnectCode} [code = DisconnectCode.RobotError] code for reason of disconnection, maps to DisconnectCode enum.
     * DisconnectCode enum is meant to be an addition to those values already defined in the Websocket API
     * @return {boolean} `false` if not connected, thus nothing to disconnect
     */
    public disconnect(code:JIBO.v1.DisconnectCodes.DisconnectCodeType = DisconnectCode.RobotError):boolean {
        if(this._isConnected || this._isAwaitingReconnect) {
            this._isConnected = false;
            this._isAwaitingReconnect = false;
            // NOTE :: Allow client to determine if isReady should be set to false

            // signal to command library to end the session
            this._commandProxy.onEndSession.emit();
            // signal to connector owner that connection has closed
            if(this._sessionEndedCB) {
                this._sessionEndedCB(code);
            }

            // clean up callbacks & proxy
            this._responseCB = null;
            this._sessionEndedCB = null;
            this._sessionId = '';
            if(this._commandProxy) {
                this._commandProxy.destroy();
                this._commandProxy = null;
            }
            return true;
        }
        // can't disconnect if we're already not connected in the first place
        return false;
    }

    /**
     * Called by connector owner to indicate the connection is down, but it may return.
     * Command library will starts a reconnect timeout upon receivig this.
     */
    public awaitReconnect():void {
        this._isConnected = false;
        this._isAwaitingReconnect = true;
        if(this._commandProxy) {
            this._commandProxy.onAwaitReconnect.emit();
        }
    }

    /**
     * Called by connector owner to send command request to command library.
     */
    public sendMessage(message:JIBO.v1.Command):void {
        if(this._commandProxy) {
            this._commandProxy.onMessage.emit(message);
        }
    }

    /**
     * Called by connector owner to let command library know a message failed to be sent.
     */
    public responseFailed(message:JIBO.v1.AllResponses):void {
        if(this._commandProxy) {
            this._commandProxy.onResponseFailed.emit(message);
        }
    }

    /**
     * Called by connector owner when ready for session to begin.
     * Use of ready may not always be required.
     */
    public ready(isReady:boolean = true):void {
        this._isReady = isReady;
        if(isReady) {
            this.onReady.emit();
        }
    }

    /**
     * Called by command library to provide a proxy
     * @param {CommandProxy} commandProxy proxy object used to communicate with CommandLibrary
     * @private
     */
    public applyProxy(commandProxy:CommandProxy):void {
        this._commandProxy = commandProxy;
        // setup listeners for events coming from command library
        commandProxy.onResponse.on(this.onResponse);
        commandProxy.onSessionClose.on(this.onSessionClose);
        commandProxy.onSessionStarted.on(this.onSessionStarted);
    }

    private onResponse(message:JIBO.v1.AllResponses):void {
        if(this._responseCB) {
            this._responseCB(message);
        }
    }

    private onSessionClose(code:JIBO.v1.DisconnectCodes.DisconnectCodeType):void {
        if(this._sessionEndedCB) {
            this._sessionEndedCB(code);
        }
    }

    private onSessionStarted(sessionId:string):void {
        this._sessionId = sessionId;
    }

}
