// Default time to allow for inactivity before existing is terminated.
const INACTIVITY_TIMEOUT = 60 * 1000;
// Default interval, in milliseconds, heartbeats are sent.
const KEEP_ALIVE_TIMEOUT = 10 * 1000;
// Default wait, in milliseconds, between heartbeats, if exceed connection is terminated.
const RECOVERY_TIMEOUT = 20 * 1000;
// Threshold time, in milliseconds, in order to log a command as being slow
const SLOW_COMMAND = 5;

// export type SendMethod = (message:AllResponses) => void;
// export type SendMessage = (id:string, data:AllEvents) => void;
// export type SendAcknowledgement = (id:string, code:ResponseCode, other?:string|any) => void;

export default class CommandLibrary {

    /**
     * Singleton instance of CommandLibrary.
     * @type {CommandLibrary}
     * @readOnly
     * @private
     */
    private static _instance:CommandLibrary;

    // manages sessions
    private _sessionManager:CommandSessionManager;
    // delegate for requestor
    private _connections:Map<string, CommandConnector>;
    // currently active CommandConnector
    private _activeConnection:CommandConnector;
    // currently active CommandProxy associated with active CommandConnector
    private _activeProxy:CommandProxy;
    // protocol version of currently active connection
    private _activeVersion:JIBO.v1.ProtocolVersions.ProtocolVersionType;
    // sourceId of active connection, passed with ACO
    private _activeSourceId:string;

    // VALIDATION

    //validator for current protocol
    private _validator:Ajv.ValidateFunction;
    //map of validators for all supported validator for protocol versions
    private _validators:Map<JIBO.v1.ProtocolVersions.ProtocolVersionType,Ajv.ValidateFunction>;
    //enable validation to check that everything uses the protocol properly.
    private _validateMessages: boolean;
    // ProtocolVerions values made into string array
    private _validVersions:string[];

    /**
     * CommandLibrary constructor
     * @param {any} jibo Instance of jibo runtime
     * @param {boolean} [validate = true] Flag deteremining if CommandLibrary shoudl validate protocol, `false` used for testing
     */
    constructor(jibo:any, validate:boolean = true) {
        // Make sure there isn't a singleton already created and war
        if (CommandLibrary._instance) {
            log.warn('CommandLibrary Singleton has already been initialized, use CommandLibrary.instance to access');
            return;
        }
        //set jibo reference for rest of the library to use, avoiding circular dependencies
        jiboRef.setJibo(jibo);
        // bind callbacks
        this.connect = this.connect.bind(this);
        this.messageReceived = this.messageReceived.bind(this);
        this.awaitReconnect = this.awaitReconnect.bind(this);
        this.startSession = this.startSession.bind(this);
        this.endSession = this.endSession.bind(this);
        this.disconnect = this.disconnect.bind(this);
        this.responseFailed = this.responseFailed.bind(this);

        // Assign as global singleton
        CommandLibrary._instance = this;
        // create map to store command connectors
        this._connections = new Map<string, CommandConnector>();
        // create manager to handle sessions
        this._sessionManager = new CommandSessionManager();
        // set up validation
        this._validateMessages = validate;
        this.createValidators();
        // convert ProtocolVersions enum into string array of values
        this._validVersions = Object.keys(ProtocolVersions).map(key => (ProtocolVersions[key]));
    }

    static createInstance(jibo: any, validate = true): void {
        CommandLibrary._instance = new CommandLibrary(jibo);
    }

    /**
     * Gets singleton instance of CommandLibrary.
     */
    static get instance():CommandLibrary {
        if(!CommandLibrary._instance){
            log.info("CommandLibrary hasn't been constructed, call constructor first.");
        }
        return CommandLibrary._instance;
    }

    /**
     * Destroy CommandLibrary and nullify its singleton
     */
    public destroy():void {
        CommandLibrary._instance = null;
        // TODO :: May need to do more thorough destruction on these
        this._connections = null;
        this._sessionManager = null;
        this._activeConnection = null;
        this._activeProxy = null;
        this._activeVersion = null;
        this._activeSourceId = '';
        this._validator = null;
        this._validators = null;
    }

    /**
     * Create a CommandConnector.
     * If there is alreayd a CommandConnector registered with taht id it will return that CommandConnector.
     */
    public createCommandConnector(id:string, startReady:boolean = true):CommandConnector {
        let commandConnect:CommandConnector = this._connections.get(id);
        if(!commandConnect) {
            // if not found make new & add to map
            commandConnect = new CommandConnector(id, this, startReady);
            this._connections.set(id, commandConnect);
        }
        return commandConnect;
    }

    /**
     * Remove reference to CommandConnector.
     * If the given CommandConnector is the active it will be disconnected.
     */
    public removeCommandConnector(connector:CommandConnector):void {
        // if connector is active, disconnect
        if(this._activeConnection === connector) {
            this.disconnect(DisconnectCode.NewConnection);
        }
        this._connections.delete(connector.id);
    }

    /**
     * Remove reference to CommandConnector by id.
     * If the given CommandConnector is the active it will be disconnected.
     */
    public removeCommandConnectorById(id:string):void {
        // if connector is active, disconnect
        let connector:CommandConnector = this._connections.get(id);
        if(connector) {
            this.removeCommandConnector(connector);
        }
    }

    /**
     * Connect delegate to command library
     * private - only called by via CommandConnector.connect()
     * @private
     */
    public connect(commandConnection:CommandConnector):void {
        // check version
        let permissions:Permissions = this.createPermissionsFromACO(commandConnection.aco);
        const sourceId:string = commandConnection.aco.sourceId;
        if(!this.isValidVersion(permissions.version)) {
            log.info(`version not accepted ${permissions.version}, connection denied`);
            return;
        }
        // check incoming connector against existing connector
        if(this._activeConnection) {
            // if connection is the same
            if(this._activeConnection === commandConnection) {
                if(this._activeConnection.isConnected){
                    if(this._activeSourceId !== sourceId) {
                        // already connected but to a different source, fully disconnect current connection
                        log.info('source ids differ, new connection interrupts previous connection');
                        this.disconnect(DisconnectCode.NewConnection);
                    }
                    else {
                        // if already connected, ignore connection attempt
                        log.info('attempting connection to same source, but already connected');
                        return;
                    }
                }
                else if(this._activeConnection.isAwaitingReconnect) {
                    if(this._activeSourceId !== sourceId) {
                        // awaiting a reconnect, but new connection is to a different source, fully disconnect current connection
                        log.info('source ids differ, new connection interrupts previous connection');
                        this.disconnect(DisconnectCode.NewConnection);
                    }
                    else {
                        // we are awaiting a reconnect from same source, wait for session message to come through
                        log.info('attempting reconnection from same source, wait for session request to restore current session');
                        return;
                    }
                }
            }
            else {
                // different connector attempt, close previous connection
                log.info(`interrupting connector ${this._activeConnection.id} with connection from connector ${commandConnection.id}`);
                this.disconnect(DisconnectCode.NewConnection);
            }
        }

        // add analytics connected event
        jiboRef.jibo.analytics.track('Remote Connected', { app_id: sourceId });

        // create proxy for Command Library
        let commandProxy:CommandProxy = new CommandProxy();
        // directives TO command library FROM command connection
        commandProxy.onMessage.on(this.messageReceived);
        commandProxy.onAwaitReconnect.on(this.awaitReconnect);
        commandProxy.onEndSession.on(this.endSession);
        commandProxy.onResponseFailed.on(this.responseFailed);

        commandConnection.applyProxy(commandProxy);
        // Also keep reference to proxy?
        this._activeProxy = commandProxy;
        // do we need this?
        this._activeConnection = commandConnection;

        // apply permissions
        this._activeVersion = permissions.version;
        this._activeSourceId = sourceId;
        this._validator = this._validators.get(this._activeVersion);
        this._activeConnection.version = permissions.version;
        this._sessionManager.permissions = permissions;
    }

    /**
     * Returns a Promise that resolves on completion of entity engine update.
     * Convenience method for testing purposes
     * @return {Promise<void>} - Promise resolving on completion of entity engine update
     * @private
     */
    public awaitUpdate():Promise<void> {
        return new Promise<void>( (resolve) => {
            let engine = this.getEngine();
            if(engine){
                engine.updateComplete.addOnce(resolve);
            } else {
                resolve();
            }
        });
    }

    /**
     * Returns a entity Engine
     * Convenience method for testing purposes
     * @return {Engine} - entity engine of current command session
     * @private
     */
    public getEngine():Engine {
        if(this._sessionManager.session){
            return this._sessionManager.session.commandManager.entityManager.engine;
        }
        return null;
    }

    private set robotId(robotId:string) {
        CommandUtil.robotId = robotId;
    }

    /**
     * Method to pass commands.
     * @method CommandManager#onMessage
     * @param {Command} data
     * @private
     */
    private messageReceived(data:JIBO.v1.Command) {
        if(this._validateMessages){
            // make sure message protocol is valid
            if(!this.validateProtocol(data)) {
                return;
            }
            // check version
            if(!this.checkVersion(data)) {
                return;
            }
        }
        // check if there is an active session and it does not match the sesion id of the request
        const sessionMismatch:boolean = this._sessionManager.checkSessionMismatch(CommandUtil.getSessionId(data, this._activeVersion));
        // check for Session command type, if true start/restore session
        if(this._sessionManager.checkSessionCommand(data)) {
            timer.start('sessionStart');
            // if there is session mismatch resolve current session
            if(sessionMismatch) {
                // TODO :: We'll probbaly want more logc to determine how sessions can override each other
                // NOTE :: For now we assume that new sessions are overriding older sessions
                // clear active session to make way for new session
                log.info('messageReceived : new session causing previous session end',data);
                this._sessionManager.endSession();
            }
            // wait for connection to be ready before starting/reconnecting session
            if (this._activeConnection.isReady) {
                this.startSession();
            } else {
                // if not ready add listener
                // there is a pending session request
                this._activeConnection.onReady.on(this.startSession);
            }
            return;
        }
        // if not a Session command, make sure there is an existing session
        else if(!this._sessionManager.session) {
            // we need an active session, if there is none then we reject the request
            this.sendAcknowledgement(data, ResponseCode.ServiceUnavailable);
            return;
        }
        // if session id of request does not match current session reject the request
        if(sessionMismatch) {
            log.info('messageReceived : session mismatch for data',data);
            this.sendAcknowledgement(data, ResponseCode.Forbidden);
            return;
        }
        // every time we receive a command, reset the inactivity timeout
        this._sessionManager.resetInactivityTimeout();
        //command has basic levels of approval, send to command library
        timer.start('startCommand');
        this._sessionManager.startCommand(data);
        let debugTime = timer.stop('startCommand');
        if (debugTime > SLOW_COMMAND) {
            log.debug(`Command Performance : time to add command ${data.Command.Type} : ${debugTime} ms`);
        }
    }

    /**
     * Handler for responses that could not be deliver, returned via a CommandConnector
     * @private
     */
    private responseFailed(message:JIBO.v1.AllResponses) {
        if(!this._sessionManager.handleFailedResponse(message)) {
            // TODO :: Could this even happen?
            // TODO :: if session couldn't handle fasiled messages, store somewhere else?
            // this._failedSends.push(message);
        }
    }

    /**
     * Start a session.
     * @private
     */
    private startSession():void {
        // remove possible listener that may have been added waiting for connection to be ready
        this._activeConnection.onReady.off(this.startSession);
        // start session, provide callbacks for response and session closure
        this._sessionManager.startSession(this._activeProxy.response, this.disconnect);
        // send session id back to connector for convenience
        this._activeProxy.sessionStarted(this._sessionManager.sessionId);
        log.debug('Command Performance : time to start session : ' + timer.stop('sessionStart') + 'ms');
    }

    /**
     * Called by CommandConnector when a connection is lost, but a reconnect is desired.
     * Would get called in the case of connection disruption.
     * @private
     */
    private awaitReconnect() {
        // try to pause the session, will wait for session to start again
        if(!this._sessionManager.handleDisconnection()) {
            // if we weren't able to pause session then end session
            this.disconnect(DisconnectCode.ReconnectError);
        }
    }

    /**
     * Called to disconnect current connection.
     * Sends disconnect request to currently active CommandConnector
     * @private
     */
    private disconnect(code:JIBO.v1.DisconnectCodes.DisconnectCodeType):void {
        // disconnect active connection
        this._activeConnection.disconnect(code);
    }

    /**
     * End the current session and nullify active connection and connection proxy
     * @private
     */
    private endSession() {
        jiboRef.jibo.analytics.track('Remote Disconnected', { app_id: this._activeSourceId });
        this._sessionManager.endSession();
        // clear out active connection
        this._activeProxy = null;
        // The command connection should clean up itself
        if(this._activeConnection) {
            this._activeConnection.onReady.off(this.startSession);
            this._activeConnection = null;
        }
    }

    /**
     * Converts ACO into a Permissions object for use by the CommandLibrary
     * @private
     */
    private createPermissionsFromACO(aco:JIBO.v1.ACO):Permissions {
       let permissions:Permissions;
        if (aco.version === 'v0') {
            log.warn(`Protocol version ${aco.version} is no longer a valid version, use 1.0 instead.`);
            aco.version = ProtocolVersions.v1;
        }
        if (aco.version === ProtocolVersions.v1){
           permissions = {
               version: aco.version,
               // commands
               attention: aco.commandSet.indexOf(CommandTypes.SetAttention) !== -1,
               display: aco.commandSet.indexOf(CommandTypes.Display) !== -1,
               getConfig: aco.commandSet.indexOf(CommandTypes.GetConfig) !== -1,
               fetchAsset: aco.commandSet.indexOf(CommandTypes.FetchAsset) !== -1,
               listen: aco.commandSet.indexOf(CommandTypes.Listen) !== -1,
               lookAt: aco.commandSet.indexOf(CommandTypes.LookAt) !== -1,
               video: aco.commandSet.indexOf(CommandTypes.Video) !== -1,
               play: aco.commandSet.indexOf(CommandTypes.Say) !== -1,
               setConfig: aco.commandSet.indexOf(CommandTypes.SetConfig) !== -1,
               takePhoto: aco.commandSet.indexOf(CommandTypes.TakePhoto) !== -1,
               // streams
               personStream: aco.streamSet.indexOf(StreamTypes.Entity) !== -1,
               motionStream: aco.streamSet.indexOf(StreamTypes.Motion) !== -1,
               hotWord: aco.streamSet.indexOf(StreamTypes.HotWord) !== -1,
               screenGesture: aco.streamSet.indexOf(StreamTypes.ScreenGesture) !== -1,
               headTouch: aco.streamSet.indexOf(StreamTypes.HeadTouch) !== -1,
               // connection values
               keepAliveTimeout: aco.keepAliveTimeout || KEEP_ALIVE_TIMEOUT,
               recoveryTimeout: aco.recoveryTimeout || RECOVERY_TIMEOUT,
               headTouchStopTime: aco.remoteConfig && aco.remoteConfig.headTouchStopTime,
               // remote mode specifics
               hideRemoteIndicator: !(aco.remoteConfig && !aco.remoteConfig.hideVisualCue),
               inactivityTimeout: aco.remoteConfig.inactivityTimeout || INACTIVITY_TIMEOUT,
               // for unit testing
               test: aco.test,
           };
       }
       else {
            log.error(`Protocol version not supported: ${aco.version}`);
           // TODO :: abort if
           return null;
       }
       return permissions;
   }

   ////////////////////// VALIDATION //////////////////////

   /**
    * Create protocol validators for supported protocol versions
    * Will need to add validators for each supported protocol
    * @private
    */
   private createValidators():void {
       this._validators = new Map<JIBO.v1.ProtocolVersions.ProtocolVersionType, Ajv.ValidateFunction>();

       // Create v1 protocol validator

       //load up the schema file
       let schema = require('@types/jibo-command-protocol/commandSchema.json');
       //create our ajv instance, telling it that we want to see all the errors
       let ajv = new Ajv({allErrors: true});
       //our schemas are built against the 04 draft, so we need to specifically add those
       //as they are somewhat older
       ajv.addMetaSchema(require('ajv/lib/refs/json-schema-draft-04.json'));
       //compile the schema into a reusable validation function
       let validator:Ajv.ValidateFunction = ajv.compile(schema);
       this._validators.set(ProtocolVersions.v1, validator);

       // TODO :: add other protocols as necessary
   }

   /**
    * Checks if data fits the protocol format of the current connection.
    * @private
    */
   private validateProtocol(data:JIBO.v1.Command):boolean {
       // check format
       if (!this._validator(data)) {
           let error = formatCommandErrors(this._validator.errors);
           log.warn('Invalid protocol: ', error);
           this.sendAcknowledgement(data, ResponseCode.BadRequest, error);
           return false;
       }
       return true;
   }

   /**
    * Checks if version matches active version, if not send appropriate response code
    * @private
    */
   private checkVersion(data:JIBO.v1.Command):boolean {
       const version:string = CommandUtil.getVersion(data);
       if(version !== this._activeVersion){
           log.warn('Version conflict, version given: ' + version);
           this.sendAcknowledgement(data,this.isValidVersion(version) ? ResponseCode.VersionConflict: ResponseCode.VersionNotSupported);
           return false;
       }
       return true;
   }

   /**
    * Checks if version string is incluced in set of supported protocols
    * @private
    */
   private isValidVersion(version:string):boolean {
       return this._validVersions.indexOf(version) !== -1;
   }

   ////////////////////// HELPERS //////////////////////

   /**
    * Helper method to send acknowledgements
    * @private
    */
   private sendAcknowledgement(command:JIBO.v1.Command, code:JIBO.v1.ResponseCodes.ResponseCodeType, data?:any):void {
       const response:JIBO.v1.AllResponses = CommandUtil.createAcknowledgement(
           this._activeVersion,
           CommandUtil.getTransactionId(command, this._activeVersion),
           CommandUtil.getSessionId(command, this._activeVersion),
           code,
           data
       );
       this._activeProxy.response(response);
   }
}
