import { Engine, NodeList, System } from '../core';
import { SetConfigNode } from '../nodes';
import { SetConfig, RequestCommand } from '../components';
import { jiboRef } from '../../jibo';
import { AsyncCommandEvent } from 'jibo-command-protocol';
//Typings only import: do not use for actual code

/**
 * AttentionSystem pushes attention modes to the expression service.
 * This system works to maintain that only one mode is pushed at a time.
 * When all AttentionNodes are removed the attention mode will return the underlying mode.
 */
export default class SetConfigSystem extends System
{
    private nodes:NodeList<SetConfigNode>;

    constructor()
    {
        super();
    }

    public addToEngine( engine:Engine ):void
    {
        this.nodes = engine.getNodeList( SetConfigNode );
    }

    public update( time:number ):void
    {
        let node:SetConfigNode = this.nodes.head;
        for( node; node; node = node.next )
        {
            let request:RequestCommand = node.request;
            if (!request.acknowledged) {
                let setConfig:SetConfig = node.setConfig;
                this.setConfigOptions(setConfig.options).then((response) =>{
                    request.addResponse(response,true);
                });
            }

        }
    }

    public removeFromEngine( engine:Engine ):void
    {
        this.nodes = null;
    }

    private setConfigOptions(options: JIBO.v1.SetConfigOptions) {
        return new Promise ((resolve, reject) => {
            jiboRef.jibo.volume.changeVolume('volumeToValue', options.Mixer * 10);
            let response: JIBO.v1.AsyncStatusEvent = {
                Event: AsyncCommandEvent.Stop
            };
            resolve(response);
        });
    }
}
