import { NodeList, System, Engine } from '../core';
import { ScreenGestureNode } from '../nodes';
import { ScreenGestureEvents, SwipeDirection } from 'jibo-command-protocol';

export default class ScreenTouchSystem extends System
{
    private nodes:NodeList<ScreenGestureNode>;
    private engine:Engine;
    private screenCoordsArray:JIBO.v1.Vector2[]=[];
    private responses:any[] = [];

    constructor()
    {
        super();
        this.onMouseDown = this.onMouseDown.bind(this);
        this.onMouseUp = this.onMouseUp.bind(this);
        this.onMouseMove = this.onMouseMove.bind(this);
    }

    public addToEngine( engine:Engine ):void
    {
        this.engine = engine;
        this.nodes = this.engine.getNodeList( ScreenGestureNode );
        document.addEventListener('mousedown', this.onMouseDown);
        document.addEventListener('mousemove', this.onMouseMove);
        document.addEventListener('mouseup', this.onMouseUp);
    }

    public removeFromEngine( engine:Engine ):void
    {
        this.nodes = null;
        document.removeEventListener('mousedown', this.onMouseDown);
        document.removeEventListener('mousemove', this.onMouseMove);
        document.removeEventListener('mouseup', this.onMouseUp);
    }

    public update( time:number ):void
    {
        let node:ScreenGestureNode = this.nodes.head;
        for (node; node; node = node.next)
        {
            for (let response of this.responses)
            {
                node.request.addResponse(response, false);
            }
        }
        // clear out responses
        this.responses.length = 0;
    }

    private onMouseDown(event:MouseEvent):void
    {
        this.screenCoordsArray.push([event.x,event.y]);
    }

    private onMouseMove(event:MouseEvent):void
    {
        this.screenCoordsArray.push([event.x,event.y]);
    }

    private onMouseUp(event:MouseEvent):void
    {
        this.getGesture();
        this.screenCoordsArray.length = 0;
    }

    private getGesture(): void
    {
        // @TODO: getGesture from api or calculate it from this.screenCoordsArray
        let xMax:number = 0;
        let xMin:number = 1280;
        let yMax:number = 0;
        let yMin:number = 720;
        const tolerance:number = 50;
        const first = this.screenCoordsArray[0];
        const last = this.screenCoordsArray[this.screenCoordsArray.length - 1];
        const xStart = first[0];
        const xEnd = last[0];
        const yStart = first[1];
        const yEnd = last[1];
        for (const point of this.screenCoordsArray)
        {
          if (point[0] < xMin) {
              xMin = point[0];
          }
          if (point[0] > xMax) {
              xMax = point[0];
          }
          if (point[1] < yMin) {
              yMin = point[1];
          }
          if (point[1] > yMax) {
              yMax = point[1];
          }
        }
        if ((yMax-yMin)>(xMax-xMin) && (yMax-yMin)>tolerance) {
            //vertical swipe
            if ((yStart - yEnd) > 0) {
                //swipe Up
                let response:JIBO.v1.SwipeEvent = {
                    Event: ScreenGestureEvents.Swipe,
                    Direction: SwipeDirection.Up
                };
                this.responses.push(response);
            } else {
                //swipe Down
                let response:JIBO.v1.SwipeEvent = {
                    Event: ScreenGestureEvents.Swipe,
                    Direction: SwipeDirection.Down
                };
                this.responses.push(response);
            }
        } else if ((xMax-xMin)>(yMax-yMin) && (xMax-xMin)>tolerance) {
            // horizontal swipe
            if ((xStart - xEnd) > 0) {
                //swipe Left
                let response:JIBO.v1.SwipeEvent = {
                    Event: ScreenGestureEvents.Swipe,
                    Direction: SwipeDirection.Left
                };
                this.responses.push(response);
            } else {
                //swipe Right
                let response:JIBO.v1.SwipeEvent = {
                    Event: ScreenGestureEvents.Swipe,
                    Direction: SwipeDirection.Right
                };
                this.responses.push(response);
            }
        } else if ((xMax-xMin)<tolerance && (yMax-yMin)<tolerance) {
            //Tap
            let response:JIBO.v1.TapEvent = {
                Event: ScreenGestureEvents.Tap,
                Coordinate: [xEnd,yEnd]
            };
            this.responses.push(response);
        }

    }
}
