import { NodeList, System, Engine } from '../core';
import { jiboRef } from '../../jibo';
import { DisplayNode } from '../nodes';
import { DisplayChange, RequestCommand } from '../components';
//Typings only import: do not use for actual code
import JiboType = require('../../../../jibo');
import {DisplayChangeType, DisplayEvents, ViewStates,
    AsyncCommandEvent, ResponseCode, DisplayErrorDetails, DisplayViewType} from 'jibo-command-protocol';

export default class DisplaySystem extends System
{
    private nodes:NodeList<DisplayNode>;

    constructor()
    {
        super();
    }

    public addToEngine( engine:Engine ):void
    {
        this.nodes = engine.getNodeList( DisplayNode );

        // TODO :: there can only be one active Look At, block others
        for( let node:DisplayNode = this.nodes.head; node; node = node.next )
        {
            this.onAdded( node );
        }
        this.nodes.nodeAdded.add( this.onAdded );
        this.nodes.nodeRemoved.add( this.onRemoved );
    }

    public update( time:number ):void
    {
        let node:DisplayNode = this.nodes.tail;
        while( node )
        {
            let displayChange:DisplayChange = node.displayChange;
            if(!displayChange.isActive) {
                displayChange.isActive = true;
                let request:RequestCommand = node.request;
                // change view
                switch(displayChange.type) {
                    case DisplayChangeType.Swap:
                        let view:JiboType.face.views.View = this.createView(node.display.view);
                        if(view) {
                            this.swapViews(view)
                            .then((view:JiboType.face.views.View) => {
                                // send opened event
                                let response: JIBO.v1.ViewStateEvent = {
                                    Event: DisplayEvents.ViewStateChange,
                                    State: ViewStates.Opened
                                };
                                request.addResponse(response, false);
                            })
                            .catch(() => {
                                // view change failed, stop command
                                console.log('update : swap view failed');
                                displayChange.isActive = false; // TODO :: Are we OK not trying to clean this up
                                let response: JIBO.v1.AsyncStatusEvent = {
                                    Event: AsyncCommandEvent.Stop,
                                };
                                request.addResponse(response, true);
                            });
                        }
                        else {
                            // invalid data
                            console.log('update : invalid view data');
                            displayChange.isActive = false; // TODO :: Are we OK not trying to clean this up?
                            let code: JIBO.v1.ResponseCodes.ResponseCodeType = ResponseCode.BadRequest;
                            let message:string = DisplayErrorDetails.MissingValues;
                            request.setAcknowledge(code,true, message);
                            // try next node
                            node = node.previous;
                            break;
                        }
                }
            }

            // end all other display command
            node = node.previous;
            for( node; node; node = node.previous )
            {
                // if not active can just dismiss via conflict
                if(!node.displayChange.isActive) {
                    node.request.setAcknowledge(ResponseCode.Conflict, true, 'active view change in process');
                }
                // stop all other display commands, can only be one active
                else {
                    node.displayChange.isActive = false;
                    let response: JIBO.v1.AsyncStatusEvent = {
                        Event: AsyncCommandEvent.Stop,
                    };
                    node.request.addResponse(response, true);
                }
            }
            node = null;
        }
    }

    public removeFromEngine( engine:Engine ):void
    {
        this.nodes = null;
    }

    private onAdded = ( node:DisplayNode ) => {
        // TODO :: Could use better logic here
    }

    private onRemoved = ( node:DisplayNode ) => {
        if(node.displayChange.isActive) {
            // remove the active view
            this.removeView().then((view:JiboType.face.views.View|null) => {
                console.log('onRemoved : remove view succeeded');
            })
            .catch(() => {
                console.log('onRemoved : remove view failed');
            });
        }
    }

    private swapViews(view:JiboType.face.views.View):Promise<JiboType.face.views.View|null> {
        return new Promise<JiboType.face.views.View>((resolve, reject) => {
            if(view) {
                jiboRef.jibo.face.views.changeView(
                    {
                        remove: true,
                        addView: view
                    },
                    resolve,
                    reject
                );
            }
        });
    }

    private removeView():Promise<JiboType.face.views.View> {
        return new Promise<JiboType.face.views.View>((resolve, reject) => {
            jiboRef.jibo.face.views.changeView(
                {
                    remove: true
                },
                resolve,
                reject
            );
        });
    }

    private createView (viewRequest:JIBO.v1.AllViews):JiboType.face.views.View
    {
        try{
            if(viewRequest){
                // TODO :: check for bad data
                // based on the view type from protocol create an actual View for the viewmager
                let view:JiboType.face.views.View;
                switch(viewRequest.Type) {
                    case DisplayViewType.Eye:
                        let eyeView:JiboType.face.views.EyeView = new jiboRef.jibo.face.views.EyeView();
                        this.setViewDefaults(eyeView, viewRequest);
                        return eyeView;
                    case DisplayViewType.Text:
                        view = this.setViewDefaults(new jiboRef.jibo.face.views.View(), viewRequest);
                        let label:JiboType.face.views.Label = new jiboRef.jibo.face.views.Label();
                        label.text = viewRequest.Text;
                        label.setTargetAnchor(.5, .5);
                        label.setTargetPosition(jiboRef.jibo.face.width/2, jiboRef.jibo.face.height/2);
                        // TODO :: apply default font, etc.
                        view.addComponent(label);
                        return view;
                    case DisplayViewType.Image:
                        view = this.setViewDefaults(new jiboRef.jibo.face.views.View(), viewRequest);
                        let clip:JiboType.face.views.Clip = new jiboRef.jibo.face.views.Clip();
                        clip.addAssetDescriptor(viewRequest.Image.name, viewRequest.Image.src, 'texture');
                        // TODO :: adjust position for clip size, should just make a custom ImageView
                        //clip.setTargetPosition(jiboRef.jibo.face.width/2, jiboRef.jibo.face.height/2);
                        view.addComponent(clip);
                        return view;
                }
            }
            else {
                console.log('swapViews : given view request was null');
            }
        }
        catch(err) {
            console.log('swapViews : error encountered creating view',err);
        }
        return null;
    }

    private setViewDefaults(view:JiboType.face.views.View, viewRequest:JIBO.v1.AllViews):JiboType.face.views.View {
        view.id = viewRequest.Name;
        view.closeOnSwipeDown = false;
        return view;
    }
}
