import CommandManager from './commander/CommandManager';
import {Session} from './commander/components';
import {Entity} from './commander/core/Entity';


export default class CommandSession {

    public messageQueue: JIBO.v1.AllResponses[];

    // session component
    public session: Session;

    // instance of a CommandManager
    public commandManager: CommandManager;

    // entity
    private _entity: Entity;

    private _sessionId:string;

    public get sessionId():string {
        return this._sessionId;
    }

    constructor(commandManager:CommandManager, entity:Entity, sessionId:string, messageQueue?:JIBO.v1.AllResponses[]) {
        this.commandManager = commandManager;
        this._sessionId = sessionId;
        entity.name = sessionId;
        this._entity = entity;
        this.session = entity.get(Session);
        this.session.id = sessionId;
        this.messageQueue = messageQueue;
    }

    public storeFailedResponse(message:JIBO.v1.AllResponses):void {
        this.session.storedEvents.push(message);
    }

    public dispose():void {
        if(this.commandManager) {
            this.commandManager.dispose();
        }
        this.clear();
    }

    public clear():void {
        this.commandManager = null;
        this.session = null;
        this._entity = null;
    }
}
