import { NodeList, System, Engine } from '../core';
import { jiboRef } from '../../jibo';
import { RequestCommand } from '../components/RequestCommand';
import { HeadTouchNode } from '../nodes';
import {HeadTouchEvents, ResponseCode} from 'jibo-command-protocol';


export default class HeadTouchSystem extends System
{
    private nodes:NodeList<HeadTouchNode>;
    private engine:Engine;
    private headPads: [boolean, boolean, boolean, boolean, boolean, boolean] = [false, false, false, false, false, false];
    private hasBeenTouched: boolean;

    constructor()
    {
        super();
    }

    public addToEngine( engine:Engine ):void
    {
        this.engine = engine;
        this.nodes = this.engine.getNodeList( HeadTouchNode );
    }

    public removeFromEngine( engine:Engine ):void
    {
        this.nodes = null;
    }

    public update( time:number ):void
    {
        // The last inserted node takes priority
        let node:HeadTouchNode = this.nodes.tail;
        if(node)
        {
            let request:RequestCommand = node.request;

            this.updatePads();
            if (this.hasBeenTouched === true){
                let response: JIBO.v1.HeadTouchEvent = {
                    Event: HeadTouchEvents.HeadTouched,
                    Pads: this.headPads
                };
                request.addResponse(response, false);
            }
            //go and mark any other nodes as busy
            for (node = node.previous; node; node = node.previous)
            {
                node.request.setAcknowledge(ResponseCode.Conflict, true);
            }
        }
    }

    private updatePads(): void
    {
        let headTouchData:any = jiboRef.jibo.system.getTouchState();
        this.headPads = headTouchData.pad_state;
        this.hasBeenTouched = headTouchData.touched;
    }
}
