import { NodeList, System, Engine } from '../core';
import { jiboRef } from '../../jibo';
import { LightRingNode } from '../nodes';
import { LightRing } from '../components';

export default class ListenRingSystem extends System
{
    private nodes:NodeList<LightRingNode>;

    constructor()
    {
        super();
    }

    public addToEngine( engine:Engine ):void
    {
        this.nodes = engine.getNodeList( LightRingNode );
        this.nodes.nodeRemoved.add( this.onRemoved );
    }

    public update( time:number ):void
    {
        // there can only be one listen at a time, the last listen request takes priority
        // TODO :: may want to force node order by priorirty at some point, but for now order of entity creation works
        let node:LightRingNode = this.nodes.head;
        for( node; node; node = node.next ){
            let lightRing:LightRing = node.lightRing;
            if(node.next) {
                lightRing.isActive = false;
            }
            else {     
                lightRing.isActive = true;
                if(lightRing.isDirty) {
                    jiboRef.jibo.expression.setLEDColor(node.lightRing.color);
                    lightRing.isDirty = false;
                }
            }
        }
    }

    private onRemoved = ( node:LightRingNode ) => {
        // if has previous node, set to thier color
        if(node.lightRing.isActive) {
            if(node.previous) {
                jiboRef.jibo.expression.setLEDColor(node.previous.lightRing.color);
                node.previous.lightRing.isActive = true;
            }
            // if no more nodes set to black
            else {
                jiboRef.jibo.expression.setLEDColor([0, 0, 0]);
            }
        }
    }

    public removeFromEngine( engine:Engine ):void
    {
        this.nodes = null;
        // reset light ring to black when removing system
        jiboRef.jibo.expression.setLEDColor([0, 0, 0]);
    }
}
