import {ResponseStrings} from 'jibo-command-protocol';

export default class CommandUtil {

    static robotId:string = '';

    static LISTEN_COLORS:[number, number, number] = [0.05, 0.73, 0.94];

    static createAcknowledgement(
        version:JIBO.v1.ProtocolVersions.ProtocolVersionType,
        transactionId:string, sessionId:string, responseCode:JIBO.v1.ResponseCodes.ResponseCodeType, data?:string|any):any {
        let event:any;
        if(version as JIBO.v1.ProtocolVersions.v1 === '1.0') {
            const header: JIBO.v1.ResponseHeader = {
                RobotID: CommandUtil.robotId,
                TransactionID: transactionId,
                SessionID: sessionId
            };
            const response:JIBO.v1.AllAcknowlegements = {
                ResponseCode: responseCode,
                ResponseString: ResponseStrings[responseCode],
                Value: responseCode >= 400 ? 'Error' : 'Success'
            };
            if(data) {
                if (responseCode >= 400) {
                    (response as any).ErrorDetail = data;
                }
                else {
                    (response as any).ResponseBody = data;
                }
            }
            event = {
                ResponseHeader: header,
                Response: response
            };
        }
        return event;
    }

    static createEvent(version:JIBO.v1.ProtocolVersions.ProtocolVersionType, transactionId:string, sessionId:string, data:JIBO.v1.AllEvents):any {
        let event:any;
        if(version as JIBO.v1.ProtocolVersions.v1 === '1.0') {
            const header: JIBO.v1.EventHeader = {
                RobotID: CommandUtil.robotId,
                TransactionID: transactionId,
                SessionID: sessionId,
                Timestamp: CommandUtil.getNetworkTime()
            };
            event = {
                EventHeader: header,
                EventBody: data
            };
        }
        return event;
    }

    // using standalone method allows us to stub for testing
    static getNetworkTime():number {
        return Date.now();
    }

    // extract version from command data
    static getVersion(data:JIBO.v1.Command,
        version:JIBO.v1.ProtocolVersions.ProtocolVersionType = "1.0" ):string {
        switch (version) {
            case '1.0' as JIBO.v1.ProtocolVersions.v1:
                if(data.ClientHeader) {
                    return data.ClientHeader.Version;
                }
                break;
        }
        return null;
    }

    // extract transaction id from command data
    static getTransactionId(data:JIBO.v1.Command,
        version:JIBO.v1.ProtocolVersions.ProtocolVersionType = '1.0' ):string {
        switch (version) {
            case '1.0' as JIBO.v1.ProtocolVersions.v1:
                if(data.ClientHeader) {
                    return data.ClientHeader.TransactionID;
                }
                break;
        }
        return null;
    }

    // extract session id from command data
    static getSessionId(data:JIBO.v1.Command, version:JIBO.v1.ProtocolVersions.ProtocolVersionType = '1.0'):string {
        switch (version) {
            case '1.0' as JIBO.v1.ProtocolVersions.v1:
                if(data.ClientHeader) {
                    return data.ClientHeader.SessionID;
                }
                break;
        }
        return null;
    }

    // extract session id from command data
    static getCommandType(data:JIBO.v1.Command, version:JIBO.v1.ProtocolVersions.ProtocolVersionType = '1.0'):string {
        switch (version) {
            case '1.0' as JIBO.v1.ProtocolVersions.v1:
                if(data.Command) {
                    return data.Command.Type;
                }
                break;
        }
        return null;
    }
}
