import uuid = require('uuid');
import { VideoEvents, ResponseCode } from 'jibo-command-protocol';
import { NodeList, System, Engine } from '../core';
import { jiboRef } from '../../jibo';
import { PhotoStreamNode } from '../nodes';
import { PhotoStream } from '../components';

//NOTE: must match that in AssetServer in SSM, so that they can agree on server uris
export const ASSET_PATH = '/assets/';

export default class PhotoStreamSystem extends System
{
    private nodes:NodeList<PhotoStreamNode>;
    private engine:Engine;

    constructor()
    {
        super();
    }

    public addToEngine(engine:Engine):void
    {
        this.engine = engine;
        this.nodes = this.engine.getNodeList( PhotoStreamNode );
        this.nodes.nodeRemoved.add( this.onRemoved );
    }

    public update(time:number):void
    {
        let node:PhotoStreamNode = this.nodes.head;
        if (node)
        {
            let stream:PhotoStream = node.stream;
            if (!stream.isActive)
            {
                node.request.setAcknowledge(ResponseCode.Accepted, false);
                stream.isActive = true;
                const url = stream.assetUrl = ASSET_PATH + uuid.v4();
                jiboRef.jibo.remote.handleVideo(url, stream.photoType);
                const response: JIBO.v1.VideoReadyEvent = {
                    Event: VideoEvents.VideoReady,
                    URI: url
                };
                node.request.addResponse(response);
            }
            //go and mark any other nodes as busy
            for (node = node.next; node; node = node.next)
            {
                node.request.setAcknowledge(ResponseCode.Conflict, true);
            }
        }
    }

    public removeFromEngine(engine:Engine):void
    {
        this.nodes = null;
    }

    private onRemoved = ( node:PhotoStreamNode ) => {
        // TODO :: Could use better logic here
        if(node.stream.isActive){
            jiboRef.jibo.remote.cancelAsset(node.stream.assetUrl);
        }
    }
}
