export class Play
{
    public textInESML:string = null;
    public speakOptions:JIBO.v1.SpeakOptions = null;
    public autoRuleConfig:JIBO.v1.AutoRuleConfig = null;

    public activated:boolean = false;
    public completed:boolean = false;
    public audioId:string = null;

    constructor(textInESML?:string, speakOptions?:JIBO.v1.SpeakOptions , autoRuleConfig?:JIBO.v1.AutoRuleConfig )
    {
        if(textInESML)
        {
            this.textInESML = textInESML;
        }
        if(speakOptions) {
            this.speakOptions = speakOptions;
        }
        if(autoRuleConfig){
            this.autoRuleConfig = autoRuleConfig;
        }
    }
}
