
export class LightRing
{
    public isActive:boolean = false;
    public duration:number;
    public isDirty:boolean = false;

    private _color:[number, number, number] = [0,0,0];
    public get color():[number, number, number] {
        return this._color;
    }
    public setColor(color:[number, number, number]):void {
        this.isDirty = true;
        this._color[0] = this._color[0];
        this._color[1] = this._color[1];
        this._color[2] = this._color[2];
    }
    public setColors(r:number, g:number, b:number):void {
        this.isDirty = true;
        this._color[0] = r;
        this._color[1] = g;
        this._color[2] = b;
    }
}
