import { NodeList, System, Engine } from '../core';
import { ClassType } from '../core/Types';
import { InterruptNode, RequestCommandNode } from '../nodes';
import { Interrupt, RequestCommand } from '../components';
import {ResponseCode} from 'jibo-command-protocol';


export default class InterruptSystem extends System
{
    private interrupts:NodeList<InterruptNode>;
    private requests:NodeList<RequestCommandNode>;

    constructor()
    {
        super();
    }

    public addToEngine( engine:Engine ):void
    {
        this.interrupts = engine.getNodeList( InterruptNode );
        this.requests = engine.getNodeList( RequestCommandNode );
    }

    public update( time:number ):void
    {
        for( let node:InterruptNode = this.interrupts.head; node; node = node.next )
        {
            if(node.interrupt.interruptAll)
            {
                this.interruptAllCommands();
                return;
            }
            else
            {
                let interruptId:string = node.interrupt.interruptId;
                if(interruptId)
                {
                    if(this.interruptCommandById(interruptId))
                    {
                        node.request.setAcknowledge(ResponseCode.OK, true, interruptId);
                    }
                    else
                    {
                        node.request.setAcknowledge(ResponseCode.OK, true, 'No command found with id: ' + interruptId);
                    }
                }
                else
                {
                    // interrupt should have an id specfied if interruptAll was false
                    node.request.setAcknowledge(ResponseCode.NotAcceptable, true, 'Id not provided');
                }
            }
        }
    }

    public removeFromEngine( engine:Engine ):void
    {
        this.interrupts = null;
        this.requests = null;
    }

    private interruptAllCommands():void
    {
        let node:RequestCommandNode = this.requests.head;
        for( node; node; node = node.next )
        {
            if(!node.entity.has(Interrupt))
            {
                this.interruptEntity(node);
            }
            else
            {
                node.request.setAcknowledge(ResponseCode.OK, true);
            }
        }
    }

    private interruptCommandById(id:string):boolean
    {
        // set appropriate RequestComands state to interrupted
        let node:RequestCommandNode = this.requests.head;
        for( node; node; node = node.next )
        {
            if(node.request.id === id)
            {
                this.interruptEntity(node);
                return true;
            }
        }
        return false;
    }

    private interruptEntity(node:RequestCommandNode):void
    {
        // remove all components except RequestCommand
        // prevents Entity entering all systems except CommandSystem
        let components:any[] = node.entity.getAll();
        for(let i = components.length - 1; i >= 0; i--)
        {
            let componentClass:ClassType<any> = components[i].constructor.prototype.constructor;
            if(componentClass !== RequestCommand)
            {
                node.entity.remove(componentClass);
            }
        }

        // update RequestCommand, we don't respond with any message in this case
        node.request.acknowledged = true;
        node.request.setComplete();
    }
}
