import uuid = require('uuid');
import {PhotoEvents, ResponseCode, AsyncCommandEvent, Camera, CameraResolution} from 'jibo-command-protocol';
import { NodeList, System, Engine } from '../core';
import { jiboRef } from '../../jibo';

import { TakePhotoNode } from '../nodes';
import { TakePhoto } from '../components';
import {CacheUtils} from 'jibo-cai-utils';
//Typings only import: do not use for actual code
import JiboType = require('../../../../jibo');

//NOTE: must match that in AssetServer in SSM, so that they can agree on server uris
export const ASSET_PATH = '/assets/';

export default class TakePhotoSystem extends System
{
    private nodes:NodeList<TakePhotoNode>;
    private engine:Engine;

    constructor()
    {
        super();
    }

    public addToEngine(engine:Engine):void
    {
        this.engine = engine;
        this.nodes = this.engine.getNodeList( TakePhotoNode );
        this.nodes.nodeRemoved.add( this.onRemoved );

    }

    public update(time:number):void
    {
        let node:TakePhotoNode = this.nodes.head;
        if (node)
        {
            let photoData:TakePhoto = node.photoData;
            if (!photoData.isActive && !photoData.assetUrl)
            {
                const media = jiboRef.jibo.media;
                photoData.isActive = true;
                let options:JiboType.media.TakePhotoParams = {
                    undistort: photoData.distortion
                };
                switch (photoData.camera) {
                    case Camera.Left:
                        options.camera = media.CameraID.LEFT;
                        break;
                    case Camera.Right:
                        options.camera = media.CameraID.RIGHT;
                        break;
                }
                switch (photoData.resolution) {
                    case CameraResolution.HighRes:
                        options.photoType = media.PhotoType.FOUR_MP;
                        break;
                    case CameraResolution.MedRes:
                        //Not supported in the enum?
                        options.photoType = media.PhotoType.FULL;
                        break;
                    case CameraResolution.LowRes:
                        options.photoType = media.PhotoType.FULL;
                        break;
                    case CameraResolution.MicroRes:
                        options.photoType = media.PhotoType.PREVIEW;
                        break;
                }
                const activeNode = node;

                this._playSound();
                jiboRef.jibo.media.takePhoto(options, (err, response) => {
                    //bail if command was cancelled/cleaned up
                    if (!activeNode.photoData || !activeNode.photoData.isActive) {
                        return;
                    }
                    //bail if photo taking had an error
                    if (err) {
                        const event:JIBO.v1.AsyncErrorEvent = {
                            Event: AsyncCommandEvent.Error,
                            EventError: {
                                ErrorString: err.message,
                                ErrorCode: 1
                            }
                        };
                        activeNode.request.addResponse(event, true);
                        return;
                    }
                    const url = photoData.assetUrl = ASSET_PATH + uuid.v4();
                    jiboRef.jibo.remote.handlePhoto(url, response.url);
                    //send response
                    const event: JIBO.v1.TakePhotoEvent = {
                        Event: PhotoEvents.TakePhoto,
                        Name: '',
                        URI: url,
                        AngleTarget: [0, 0],
                        PositionTarget: [0, 0, 0]
                    };
                    activeNode.request.addResponse(event, true);
                    //mark command as not active so that when the node is removed, we don't
                    //cancel the asset (which will happen on its own)
                    activeNode.photoData.isActive = false;
                    //trigger an update so that the response will be sent
                    this.engine.requestUpdate();
                });
            }
            //go and mark any other nodes as busy
            for (node = node.next; node; node = node.next)
            {
                node.request.setAcknowledge(ResponseCode.Conflict, true);
            }
        }
    }

    private async _playSound() {
        await new Promise<void>((resolve, reject) => {
            if(!CacheUtils.initialized) {
                reject(new Error(`Global cache not initialized`));
                return;
            }

            const sound = jiboRef.jibo.loader.cached(
                'photo',
                'global-gui' //jibo.rendering.gui.ViewManager.GLOBAL_CACHE
            );
            
            if (sound) {
                sound.play();
                resolve();
            } else {
                reject();
            }
        });
    }

    public removeFromEngine(engine:Engine):void
    {
        this.nodes = null;
    }

    private onRemoved = ( node:TakePhotoNode ) => {
        // TODO :: Could use better logic here
        if(node.photoData.isActive) {
            jiboRef.jibo.remote.cancelAsset(node.photoData.assetUrl);
            node.photoData.isActive = false;
        }
    }
}
