import { NodeList, System, Engine } from '../core';
import { TestNode } from '../nodes';
import { ResponseCode } from 'jibo-command-protocol';

export default class TestSystem extends System
{
    // For Debug
    // flag to switch system between processing one node at a time or all nodes
    public isBlocking:boolean = false;

    private nodes:NodeList<TestNode>;
    private engine:Engine;

    constructor()
    {
        super();
    }

    public addToEngine( engine:Engine ):void
    {
        this.engine = engine;
        this.nodes = this.engine.getNodeList( TestNode );

        // TODO :: there can only be one active Look At, block others
        for( let node:TestNode = this.nodes.head; node; node = node.next )
        {
            this.onAdded( node );
        }
        this.nodes.nodeAdded.add( this.onAdded );
        this.nodes.nodeRemoved.add( this.onRemoved );
    }

    public update( time:number ):void
    {
        let node:TestNode = this.nodes.head;
        if(!this.isBlocking) {
            // 'process' all nodes
            for( node; node; node = node.next )
            {
                //console.log('TestSystem : update : message: ' + node.test.message);
            }
        }
        else {
            // 'process' only the first node
            //console.log('TestSystem : update : message: ' + node.test.message);
            // set all other node to conflicted
            node = node.next;
            for( node; node; node = node.next )
            {
                node.request.setAcknowledge(ResponseCode.Conflict, true);
                //console.log('TestSystem : update : conflict for request of id: ' + node.request.id);
            }
        }

    }

    public removeFromEngine( engine:Engine ):void
    {
        //console.log('TestSystem : removeFromEngine');
        this.nodes = null;
    }

    private onAdded = ( node:TestNode ) => {
        //console.log('TestSystem : onAdded : ' + node.request.id);
    }

    private onRemoved = ( node:TestNode ) => {
        //console.log('TestSystem : onRemoved : ' + node.request.id);
    }
}
