import {Event} from 'jibo-typed-events';

/**
 * Proxy for CommandLibrary
 */
export default class CommandProxy {

    // TO Command library

    // Delegate signals to pause session, session will wait for start
    public onAwaitReconnect:Event<void>;
    // Delegate signals to end session
    public onEndSession:Event<void>;
    // Delegate signals to send message
    public onMessage:Event<JIBO.v1.Command>;
    // Delegate signals to send message
    public onResponseFailed:Event<JIBO.v1.AllResponses>;

    // FROM command library

    // Delegate signals to send message
    public onResponse:Event<JIBO.v1.AllResponses>;
    // Delegate signals to send message
    public onSessionClose:Event<number>;
    // Delegate signals to session has begun, returns sessionId
    public onSessionStarted:Event<string>;

    constructor () {
        // methods used to communicate FROM command library
        this.response = this.response.bind(this);
        this.sessionClose = this.sessionClose.bind(this);
        // create events used to communicate TO command library
        this.onAwaitReconnect = new Event<void>('Pause session');
        this.onEndSession = new Event<void>('End session, external cause');
        this.onMessage = new Event<JIBO.v1.Command>('Send command');
        this.onResponseFailed = new Event<JIBO.v1.AllResponses>('Response failed command');
        this.onResponse = new Event<JIBO.v1.AllResponses>('Command response');
        this.onSessionClose = new Event<number>('Session ended, internal cause');
        this.onSessionStarted = new Event<string>('Session started');
    }

    /**
     * Called by Command Library to send response message out
     * @private
     */
    public response(message:JIBO.v1.AllResponses):void {
        this.onResponse.emit(message);
    }

    /**
     * Called by Command Library when session is closed by commaand library
     * Generally called due to inactivity or reconnect timeout
     * @private
     */
    public sessionClose(code:number):void {
        this.onSessionClose.emit(code);
    }

    /**
     * Called by Command Library to notify when session has started.
     * You can get this same information for the start session response, this is a convenience method
     * @private
     */
    public sessionStarted(sessionId:string):void {
        this.onSessionStarted.emit(sessionId);
    }

    // cleanup event listeners
    public destroy():void {
        if(this.onAwaitReconnect) {
            this.onAwaitReconnect.removeAllListeners();
            this.onAwaitReconnect = null;
        }
        if(this.onEndSession) {
            this.onEndSession.removeAllListeners();
            this.onEndSession = null;
        }
        if(this.onMessage) {
            this.onMessage.removeAllListeners();
            this.onMessage = null;
        }
        if(this.onResponse) {
            this.onResponse.removeAllListeners();
            this.onResponse = null;
        }
        if(this.onSessionClose) {
            this.onSessionClose.removeAllListeners();
            this.onSessionClose = null;
        }
    }

}
