import { Engine, NodeList, System } from '../core';
import { RequestCommandNode, SessionNode } from '../nodes';
import { RequestCommand, Session } from '../components';
import CommandUtil from '../../CommandUtil';


export default class CommandSystem extends System
{
    private commandNodes:NodeList<RequestCommandNode>;
    private sessionNodes:NodeList<SessionNode>;
    private engine:Engine;

    constructor()
    {
        super();
    }

    public addToEngine( engine:Engine ):void
    {
        this.engine = engine;
        this.commandNodes = engine.getNodeList( RequestCommandNode );
        this.sessionNodes = engine.getNodeList( SessionNode );
    }

    public update( time:number ):void
    {
        let node:RequestCommandNode = this.commandNodes.head;

        const sessionNode:SessionNode = this.sessionNodes.tail;
        // if we have a session, then process commands
        if(sessionNode) {
            // if we restore connection dispatch any stored events
            if(sessionNode.session.reconnection){
                // send a message for each response
                for(let i = 0; i < sessionNode.session.storedEvents.length; i++) {
                    sessionNode.session.sendMethod(sessionNode.session.storedEvents[i]);
                }
                sessionNode.session.storedEvents.length = 0;
                sessionNode.session.reconnection = false;
            }
            // process commands
            for( node; node; node = node.next )
            {
                if(node.request.isDirty)
                {
                    // send an acknowledgement once command has reached end of its first update cycle
                    if(!node.request.acknowledged)
                    {
                        this.sendEvent(sessionNode.session, this.createAcknowledgement(sessionNode.session, node.request));
                        node.request.acknowledged = true;
                    }

                    // send any requests
                    if(node.request.responses.length > 0) {
                        this.sendMessages(node.request, sessionNode.session);
                    }

                    // if complete
                    if(node.request.complete) {
                        this.engine.removeEntity(node.entity);
                    }
                    else {
                        node.request.clean();
                    }
                }
            }
        }
        // we don't have a session, so don't process commands
    }

    public removeFromEngine( engine:Engine ):void
    {
        this.commandNodes = null;
        this.engine = engine;
    }

    private sendEvent(session:Session, data:JIBO.v1.AllResponses):void
    {
        if(session.hasConnection) {
            session.sendMethod(data);
        }
        else {
            // store message to send on reconnect
            session.storedEvents.push(data);
        }
    }

    private sendMessages(request:RequestCommand, session:Session):void
    {
        // send a message for each response
        for(let i = 0; i < request.responses.length; i++) {
            this.sendEvent(session, this.createEvent(session, request, request.responses[i]));
        }
        // clear responses
        request.responses.length = 0;
    }

    private createAcknowledgement(ses:Session, req:RequestCommand):any
    {
        return CommandUtil.createAcknowledgement(req.version,req.id,ses.id,req.acknowledgeCode,req.acknowledgeData);
    }

    private createEvent(ses:Session, req:RequestCommand, data:JIBO.v1.AllEvents):any
    {
        return CommandUtil.createEvent(req.version,req.id,ses.id,data);
    }
}
