
export class RemoteIndicator
{
    // Settings

    // Dot settings
    public dotColor:string = '0xFF00FF';
    public dotRadius:number = 15;
    public horizontalOffset: number = 45;
    public verticalOffset: number = 45;
    public minAlpha:number = 0.3;
    public maxAlpha:number = 1;

    //Timing settings: seconds per half-cycle (min->max or max->min)
    public duration:number = 2;

    // Ring settings
    
    public minHexColor:string = '0x330033';
    public maxHexColor:string = '0xFF00FF';

    // State and auxiliar variables
    // Used to convert from hexColor to an LED friendly format
    public minLEDColor:[number, number, number] = [0,0,0];
    public maxLEDColor:[number, number, number] = [0,0,0];

    public deltaInColor:[number, number, number] = [0,0,0];
    public deltaAlpha: number = 0;
    // whether pulse is increasing or decreasing
    public lerpIsRising:boolean = true;
    // pulse time, once timer reaches an extreme it reverses direction
    public timer:number = 0;

    // reference to watermark
    public icon:PIXI.Container = null;
}
