import { NodeList, System, Engine } from '../core';
import { jiboRef } from '../../jibo';
import * as THREE from '@jibo/three';
import { LookAtNode } from '../nodes';
import { LookAt } from '../components';
import { RequestCommand } from '../components/RequestCommand';

import { AsyncCommandEvent, ResponseCode, LookAtEvents } from 'jibo-command-protocol';
import {typeguards} from 'jibo-command-protocol';


interface Point {
    x:number;
    y:number;
}

interface CameraParameters {
    width: number;
    height: number;
    center: Point;
    focalLength: Point;
    distortion: number[];
}

export default class LookAtSystem extends System
{
    private nodes:NodeList<LookAtNode>;
    private cameraParameters:CameraParameters;
    private screenSize:JIBO.v1.Vector2 = [640,360];

    constructor()
    {
        super();
        this.getCameraParameters();
    }

    public addToEngine( engine:Engine ):void
    {
        this.nodes = engine.getNodeList( LookAtNode );
        this.nodes.nodeRemoved.add( this.onRemoved );
    }

    public update( time:number ):void
    {
        let node:LookAtNode = this.nodes.head;
        for( node; node; node = node.next )
        {
            let lookAt:LookAt = node.lookAt;
            let request:RequestCommand = node.request;
            if (node.next)
            {
                if (request.acknowledged) {
                    let response: JIBO.v1.AsyncErrorEvent = {
                        Event: AsyncCommandEvent.Error,
                        EventError: {
                            ErrorString: "Target overwritten",
                            ErrorCode: 1
                        }
                    };
                    request.addResponse(response,true);
                } else {
                    let code: JIBO.v1.ResponseCodes.ResponseCodeType;
                    code = ResponseCode.Conflict;
                    request.setAcknowledge(code,true);
                }
                node.lookAt.interrupted = true;
            } else {
                if (!lookAt.isActive) {
                    let target:any = {
                        position: null
                    };
                    //@TODO: add entity support
                    const lookAtTarget = node.target.lookAtTarget;
                    if (typeguards.isPositionTarget(lookAtTarget)) {
                        target.position = {
                            x:lookAtTarget.Position[0],
                            y:lookAtTarget.Position[1],
                            z:lookAtTarget.Position[2]
                        };
                    } else if (typeguards.isAngleTarget(lookAtTarget)) {
                        target.position = this.angles2XYZ(lookAtTarget.Angle);
                    } else if (typeguards.isCameraTarget(lookAtTarget)) {
                        target.position = this.screencords2XYZ(lookAtTarget);
                    } else if (typeguards.isEntityTarget(lookAtTarget)) {
                        //@TODO: the entity 3D position could be updated in the PersonEntitySystem
                        target.position = this.entity2XYZ(lookAtTarget.Entity);
                    }
                    if (target.position)
                    {
                        lookAt.isActive = true;
                        jiboRef.jibo.expression.acquireTarget(target).then((acquireHandle) => {
                            acquireHandle.promise.then((result) => {
                                let response: JIBO.v1.AsyncErrorEvent|JIBO.v1.LookAtAchievedEvent;
                                if (result === "SUCCEEDED") {
                                    response = {
                                        Event: LookAtEvents.LookAtAchieved,
                                        PositionTarget: [0,0,0],//@TODO: should be computed
                                        AngleTarget: [0,0] //@TODO: should be computed
                                    };
                                } else {
                                    response = {
                                        Event: AsyncCommandEvent.Error,
                                        EventError: {
                                            ErrorString: "Target overwritten",
                                            ErrorCode: 1
                                        }
                                    };
                                }
                                request.addResponse(response,true);
                            });
                        });
                    } else {
                        let response:JIBO.v1.AsyncErrorEvent = {
                            Event: AsyncCommandEvent.Error,
                            EventError: {
                                ErrorString: "Bad target",
                                ErrorCode: 2
                            }
                        };
                        request.addResponse(response, true);
                    }
                }
            }
        }
    }

    public removeFromEngine( engine:Engine ):void
    {
        this.nodes = null;
    }

    private entity2XYZ(lookAtEntity: JIBO.v1.LookAtEntity): THREE.Vector3
    {
        let lpsData:any = jiboRef.jibo.lps.motionData;
        for (let entity of lpsData.entities)
        {
            if (entity.description = "person")
            {
                let hasParts = entity.parts.some((part) => {
                    return ((part.key === "head") || (part.key === "face"));
                });
                if (hasParts) {
                    if (lookAtEntity === entity.id) {
                        return entity.position;
                    }
                }
            }
        }
        return null;
    }

    private angles2XYZ(angles: JIBO.v1.AngleVector): THREE.Vector3
    {
        const head = jiboRef.jibo.expression.features.head;
        let actualPosition: THREE.Vector3 = head.direction.clone().add(head.position);
        let up:THREE.Vector3 = new THREE.Vector3(0, 0, 1);
        let perpendicular:THREE.Vector3 = actualPosition.clone().cross(up);
        let auxVector:THREE.Vector3 =  actualPosition.clone().applyAxisAngle(up,angles[0]);
        let target:THREE.Vector3 = auxVector.clone().applyAxisAngle(
            perpendicular.clone().applyAxisAngle(up, angles[0]), angles[1]
        );
        return target;
    }

    private screencords2XYZ(target: JIBO.v1.CameraTarget): THREE.Vector3 {
        let screencords:JIBO.v1.Vector2 = [null,null];
        let cx:number = this.cameraParameters.center.x;
        let cy:number = this.cameraParameters.center.y;
        let fx:number = this.cameraParameters.focalLength.x;
        let fy:number = this.cameraParameters.focalLength.y;
        if (target.ScreenSize) {
            screencords[0] = target.ScreenCoords[0]*this.cameraParameters.width/target.ScreenSize[0];
            screencords[1] = target.ScreenCoords[1]*this.cameraParameters.height/target.ScreenSize[1];
        }else{
            screencords[0] = target.ScreenCoords[0]*this.cameraParameters.width/this.screenSize[0];
            screencords[1] = target.ScreenCoords[1]*this.cameraParameters.height/this.screenSize[1];
        }
        let n_pix:JIBO.v1.Vector2 = [(screencords[0] - cx) / fx, (screencords[1] - cy) / fy];
        let k1:number = this.cameraParameters.distortion[0];
        let k2:number = this.cameraParameters.distortion[1];
        let k3:number = this.cameraParameters.distortion[4];
        let p1:number = this.cameraParameters.distortion[2];
        let p2:number = this.cameraParameters.distortion[3];
        let nd_pix:JIBO.v1.Vector2 =[n_pix[0],n_pix[1]];
        for (let i = 0; i<20;i++)
        {
            let r_2:number = Math.pow(nd_pix[0], 2)+Math.pow(nd_pix[1], 2);
            let r_4:number = r_2*r_2;
            let r_6:number = r_2*r_4;
            let k_radial:number = 1+k1*r_2+k2*r_4+k3*r_6;
            let delta_x:number = 2*p1*nd_pix[0]*nd_pix[1] + p2*(r_2+2*Math.pow(nd_pix[0],2));
            let delta_y:number = p1*(r_2+2*Math.pow(nd_pix[1],2)) + 2*p2*nd_pix[0]*nd_pix[1];
            nd_pix[0] = (n_pix[0]-delta_x)/k_radial;
            nd_pix[1] = (n_pix[1]-delta_y)/k_radial;
        }
        let u_pix:JIBO.v1.Vector2 = [nd_pix[0] * fx + cx, nd_pix[1] * fy + cy];
        let theta:number = Math.atan((u_pix[0]-cx)/fx);
        let psi:number = -Math.atan((u_pix[1]-cy)/fy);
        let angles:JIBO.v1.AngleVector = [theta,psi];
        return this.angles2XYZ(angles);
    }

    private getCameraParameters():void
    {
        // Default value to avoid no data calibration error in development
        this.cameraParameters = {
            width: 1280,
            height: 720,
            center: {
              x: 657.3223266601562,
              y: 378.8253479003906
            },
            focalLength: {
              x: 783.9614868164062,
              y: 784.0986328125
            },
            distortion: [
              -0.36631643772125244,
              0.1101401150226593,
              0.0009784416761249304,
              0.0012007149634882808,
              0
            ]
        };
        try{
            jiboRef.jibo.lps.getCameraParameters(0, (err, data) => {
                if (data && this.isCameraParameters(data)){
                    this.cameraParameters = data;
                }
            });
        }
        catch(e){
            // if we get an erro just keep the default
        }
    }

    private onRemoved = ( node:LookAtNode ) => {
        if(node.lookAt.isActive && !node.lookAt.interrupted){
            let actualPosition: THREE.Vector3 = jiboRef.jibo.expression.features.head.direction.clone().add(jiboRef.jibo.expression.features.head.position);
            jiboRef.jibo.expression.acquireTarget({position: actualPosition});
        }
    }

    private isCameraParameters(data: any): data is CameraParameters {
        return typeof data === 'object' && 'focalLength' in data;
    }
}
