import { Entity, Engine } from './core';
import { CommandTypes, StreamTypes, ResponseCode } from 'jibo-command-protocol';
import {
    RequestCommand,
    Attention,
    HotWord,
    Interrupt,
    PersonStream,
    MotionStream,
    TakePhoto,
    PhotoStream,
    Play,
    LookAt,
    Target,
    SetConfig,
    GetConfig,
    Display,
    DisplayChange,
    ScreenGesture,
    FetchAsset,
    UnloadAsset,
    AssetCache,
    HeadTouch,
    Listen,
    LightRing,
    Session
} from './components';
import { Permissions } from '../Permissions';
// Import specific command interfaces in order to be able to support different versions
// of the protocol in the future

import { Test } from './components';
import { TestRequest } from './components/Test';

export default class CommandCreator
{
    // resource components, shared between entities to manage singel resource usage
    private _permissions:Permissions;

    private _engine:Engine;

    private version: JIBO.v1.ProtocolVersions.ProtocolVersionType;

    constructor(engine:Engine, permissions:Permissions)
    {
        this._engine = engine;
        this._permissions = permissions;
        this.version = permissions.version;
    }

    public commandFromRequestProtocol(data:JIBO.v1.Command):Entity
    {
        // TODO :: can we provide an useful id to the CommandEntity?
        let commandEntity:Entity = new Entity();

        // create command component, CommandSystem created by default
        let request:RequestCommand = new RequestCommand(data);
        request.version = this.version;
        commandEntity.name = request.id;
        commandEntity.add(request);

        // parse request body into Components
        // body includes unique command types
        let body = data.Command;
        switch (body.Type) {
            case CommandTypes.StartSession:
                // InterruptSystem created by default
                this.createSession(commandEntity, request, body);
                break;
            case CommandTypes.Cancel:
                // InterruptSystem created by default
                this.createInterrupt(commandEntity, request, body);
                break;
            case CommandTypes.LookAt:
                this.createLookAt(commandEntity, request, body);
                break;
            case CommandTypes.Say:
                this.createPlay(commandEntity, request, body);
                break;
            case CommandTypes.SetAttention:
                this.createAttention(commandEntity, request, body);
                break;
            case CommandTypes.Subscribe:
                //subscribe to many things here, including LPS stream
                switch(body.StreamType) {
                    case StreamTypes.Entity:
                        this.createPersonStream(commandEntity, request, body);
                        break;
                    case StreamTypes.HotWord:
                        this.createHotWord(commandEntity, request, body);
                        break;
                    case StreamTypes.ScreenGesture:
                        this.createScreenGesture(commandEntity, request, body);
                        break;
                    case StreamTypes.Motion:
                        this.createMotionStream(commandEntity, request, body);
                        break;
                    case StreamTypes.HeadTouch:
                        this.createHeadTouch(commandEntity, request, body);
                        break;
                }
                break;
            case CommandTypes.TakePhoto:
                this.createTakePhoto(commandEntity, request, body);
                break;
            case CommandTypes.Video:
                this.createPhotoStream(commandEntity, request, body);
                break;
            case CommandTypes.SetConfig:
                this.createSetConfig(commandEntity, request, body);
                break;
            case CommandTypes.GetConfig:
                this.createGetConfig(commandEntity, request, body);
                break;
            case CommandTypes.Display:
                this.createDisplay(commandEntity, request, body);
                break;
            case CommandTypes.FetchAsset:
                this.createFetchAsset(commandEntity, request, body);
                break;
            case CommandTypes.UnloadAsset:
                this.createUnloadAsset(commandEntity, request, body);
                break;
            case CommandTypes.Listen:
                this.createListen(commandEntity, request, body);
                break;
            default:
                if((<any>body).Type === 'Test') {
                    this.createTest(commandEntity, request, body);
                    break;
                }
                request.setAcknowledge(ResponseCode.NotFound, true);
                break;
        }

        return commandEntity;
    }

    // Those are the different methods that will allow to implement different
    // versions of the protocol

    // Each methods receives the created commandEntity, the request, and the
    // required parameters, so they can manage the response code if there is a
    // problem or the application does not have the appropiate permissions.

    // TODO Once we actually have different protocol versions,
    //      we should add the logic to support them inside the methods.
    //      Ex: if (this.protocolVersion === ProtocolVersions.v1){...}else{...}

    private createSession(commandEntity:Entity, request:RequestCommand, body:JIBO.v1.SessionRequest):void{
        const session:Session = new Session();
        // convert to seconds
        session.inactivityTimeout = this._permissions.inactivityTimeout / 1000;
        // TODO :: don't want to hard code this, should come down with ACO?
        session.reconnectTimeout = 10;
        if(this._permissions.headTouchStopTime) {
            session.headTouchStopTime = this._permissions.headTouchStopTime;
        }
        commandEntity.add(session);
    }

    private createInterrupt(commandEntity:Entity, request:RequestCommand, body:JIBO.v1.CancelRequest):void{
        commandEntity.add(new Interrupt(body.ID));
    }

    private createLookAt(commandEntity:Entity, request:RequestCommand, body:JIBO.v1.LookAtRequest):void{

        if (this._permissions.lookAt) {
            commandEntity.add(new LookAt(body.TrackFlag, body.LevelHeadFlag));
            commandEntity.add(new Target(body.LookAtTarget));
        } else {
            request.setAcknowledge(ResponseCode.Forbidden, true);
        }
    }

    private createPlay(commandEntity:Entity, request:RequestCommand, body:JIBO.v1.SayRequest):void{
        if (this._permissions.play) {
            commandEntity.add(new Play(body.ESML, body.SpeakOptions, body.AutoRuleConfig));
        } else {
            request.setAcknowledge(ResponseCode.Forbidden, true);
        }
    }

    private createAttention(commandEntity:Entity, request:RequestCommand, body:JIBO.v1.AttentionRequest):void{
            commandEntity.add(new Attention(body.Mode));
    }

    private createPersonStream(commandEntity:Entity, request:RequestCommand, body:JIBO.v1.EntityRequest):void{
        if (this._permissions.personStream) {
            commandEntity.add(new PersonStream());
        } else {
            request.setAcknowledge(ResponseCode.Forbidden, true);
        }
    }

    private createHotWord(commandEntity:Entity, request:RequestCommand, body:JIBO.v1.HotWordRequest):void{
        if (this._permissions.hotWord) {
            commandEntity.add(new HotWord());
        } else {
            request.setAcknowledge(ResponseCode.Forbidden, true);
        }
    }

    private createScreenGesture(commandEntity:Entity, request:RequestCommand, body:JIBO.v1.ScreenGestureRequest):void{
        if (this._permissions.screenGesture) {
            commandEntity.add(new ScreenGesture());
        } else {
            request.setAcknowledge(ResponseCode.Forbidden, true);
        }
    }

    private createMotionStream(commandEntity:Entity, request:RequestCommand, body:JIBO.v1.MotionRequest):void{
        if (this._permissions.motionStream) {
            commandEntity.add(new MotionStream());
        } else {
            request.setAcknowledge(ResponseCode.Forbidden, true);
        }
    }

    private createHeadTouch(commandEntity:Entity, request:RequestCommand, body:JIBO.v1.HeadTouchRequest):void{
        if (this._permissions.headTouch) {
            commandEntity.add(new HeadTouch());
        } else {
            request.setAcknowledge(ResponseCode.Forbidden, true);
        }
    }

    private createTakePhoto(commandEntity:Entity, request:RequestCommand, body:JIBO.v1.TakePhotoRequest):void{
        if (this._permissions.takePhoto) {
            commandEntity.add(new TakePhoto(body.Distortion, body.Camera, body.Resolution));
        } else {
            request.setAcknowledge(ResponseCode.Forbidden, true);
        }
    }

    private createPhotoStream(commandEntity:Entity, request:RequestCommand, body: JIBO.v1.VideoRequest):void{
        if (this._permissions.video) {
            commandEntity.add(new PhotoStream(body.VideoType));
        } else {
            request.setAcknowledge(ResponseCode.Forbidden, true);
        }
    }

    private createSetConfig(commandEntity:Entity, request:RequestCommand, body: JIBO.v1.SetConfigRequest):void{
        if (this._permissions.setConfig) {
            commandEntity.add(new SetConfig(body.Options));
        } else {
            request.setAcknowledge(ResponseCode.Forbidden, true);
        }
    }

    private createGetConfig(commandEntity:Entity, request:RequestCommand, body: JIBO.v1.GetConfigRequest):void{
        if (this._permissions.getConfig) {
            commandEntity.add(new GetConfig());
        } else {
            request.setAcknowledge(ResponseCode.Forbidden, true);
        }
    }

    private createDisplay(commandEntity:Entity, request:RequestCommand, body: JIBO.v1.DisplayRequest):void{
        if (this._permissions.display) {
            commandEntity.add(new Display(body.View));
            commandEntity.add(new DisplayChange());
        } else {
            request.setAcknowledge(ResponseCode.Forbidden, true);
        }
    }

    private createFetchAsset(commandEntity:Entity, request:RequestCommand, body: JIBO.v1.FetchAssetRequest):void{
        if (this._permissions.fetchAsset) {
            commandEntity.add(new FetchAsset(body.Name, body.URI));
            commandEntity.add(this._engine.getEntityByName("assetCache").get(AssetCache));
        } else {
            request.setAcknowledge(ResponseCode.Forbidden, true);
        }
    }

    private createUnloadAsset(commandEntity:Entity, request:RequestCommand, body: JIBO.v1.UnloadAssetRequest):void{
        if (this._permissions.fetchAsset) {
            commandEntity.add(new UnloadAsset(body.Name));
            commandEntity.add(this._engine.getEntityByName("assetCache").get(AssetCache));
        } else {
            request.setAcknowledge(ResponseCode.Forbidden, true);
        }
    }

    private createListen(commandEntity:Entity, request:RequestCommand, body: JIBO.v1.ListenRequest):void{
        if (this._permissions.listen) {
            commandEntity.add(new Listen(body.LanguageCode, body.MaxNoSpeechTimeout, body.MaxSpeechTimeout));
            commandEntity.add(new LightRing());
        } else {
            request.setAcknowledge(ResponseCode.Forbidden, true);
        }
    }

    private createTest(commandEntity:Entity, request:RequestCommand, body: any):void{
        if (this._permissions.test) {
            commandEntity.add(new Test(<TestRequest>body));
        } else {
            request.setAcknowledge(ResponseCode.Forbidden, true);
        }
    }
}
