import Ajv = require('ajv');

export function formatCommandErrors(errors:Ajv.ErrorObject[]) {
    //filter errors to one about our expected command, if possible
    const filtered = errors.filter(isCommandSpecific);
    return formatGeneralErrors(filtered.length ? filtered : errors);
}

function isCommandSpecific(error:any) {
    //error is untyped instead of Ajv.ErrorObject because error.parentSchema is defined as {} not any
    //see if the original data had a specific command type specified
    if (error.data && error.data.Type) {
        const type = error.data.Type;
        //if if the error's parent schema had this type as the expected type - that means that
        //we were looking at a specific Command, and not looking at a different command not
        //specified by the Type variable
        if (error.parentSchema && error.parentSchema.properties &&
            error.parentSchema.properties.Type && error.parentSchema.properties.Type.enum &&
            error.parentSchema.properties.Type.enum[0] === type) {
            return true;
        }
    }
    return false;
}

function formatGeneralErrors(errors:Ajv.ErrorObject[]) {
    return errors.map(formatError).join('\n');
}

//function for formatting errors from Ajv to be more readable in logs, as well as having less
//unimportant data
function formatError(error:Ajv.ErrorObject) {
    //turn the basics into a useful error message
    let output = error.dataPath + ' ' + error.message;
    //if it was an additionalProperties error, then we can name the additional property that was found
    if (error.keyword === 'additionalProperties') {
        //dunno why the Ajv.ErrorParameters interface doesn't have `additionalProperty`, because
        //I can see it in the actual output.
        output += ' - found property ' + (error.params as any).additionalProperty;
    }
    return output;
}