import { NodeList, System, Engine } from '../core';
import { jiboRef } from '../../jibo';
import { UnloadAssetNode } from '../nodes';
import { UnloadAsset, RequestCommand } from '../components';
import {ResponseCode, UnloadAssetEvents, UnloadAssetErrorDetails} from 'jibo-command-protocol';

export default class UnloadAssetsSystem extends System
{
    private nodes:NodeList<UnloadAssetNode>;
    private engine:Engine;

    constructor()
    {
        super();
    }

    public addToEngine( engine:Engine ):void
    {
        this.engine = engine;
        this.nodes = this.engine.getNodeList( UnloadAssetNode );
    }

  public update( time:number ):void
  {
      let node:UnloadAssetNode = this.nodes.head;
      for (node; node; node = node.next)
      {
          let unloadAsset:UnloadAsset = node.unloadAsset;
          let request:RequestCommand = node.request;
          if (!request.acknowledged) {
              if (!unloadAsset.name || !node.assetCache.assetTokens.has(unloadAsset.name) ) {
                  const code: JIBO.v1.ResponseCodes.ResponseCodeType = ResponseCode.NotAcceptable;
                  request.setAcknowledge(code, true, UnloadAssetErrorDetails.InvalidName);
              }else {
                  let assetToken = node.assetCache.assetTokens.get(unloadAsset.name);
                  if(assetToken){
                      jiboRef.jibo.loader.unload(assetToken.assetToken);
                      node.assetCache.assetTokens.delete(unloadAsset.name);
                      let response: JIBO.v1.UnloadAssetEvent;
                      response = {
                              Event: UnloadAssetEvents.UnloadAssetDone,
                              Detail: unloadAsset.name
                          };
                      request.addResponse(response,true);
                  }
              }
          }
      }
  }

    public removeFromEngine( engine:Engine ):void
    {
        // this.nodes = null;
    }
}
