export class LookAt
{
    public isActive:boolean = false;
    public interrupted: boolean = false;
    public trackFlag: boolean = false;
    public levelHeadFlag: boolean = false;

    constructor(trackFlag:boolean = false, levelHeadFlag: boolean = false)
    {
        this.trackFlag = trackFlag;
        this.levelHeadFlag = levelHeadFlag;
    }
}
