import JiboType = require('../../../../jibo');

export class Listen
{
    public isActive:boolean = false;
    public mim:JiboType.bt.behaviors.Mim;
    public speech:JiboType.jetstream.types.ListenResult;

    public language: string;
    public maxNoSpeechTimeout:number;
    public maxSpeechTimeout:number;

    constructor(language:string = "en-US", maxNoSpeechTimeout:number = 15000, maxSpeechTimeout:number = 15000)
    {
        this.language = language;
        this.maxSpeechTimeout = maxSpeechTimeout;
        this.maxNoSpeechTimeout = maxNoSpeechTimeout;
    }

    public onMimEnd(results:JiboType.bt.behaviors.MimResult) {
        //TODO Use a constant like jetstream.types.ListenResultState.match
        if (results.asrResults.state === "match"){
            this.speech = results.asrResults;
        } else {
            this.speech = null;
        }
    }
}
