import { Engine, Entity } from './core';
import CommandCreator from './CommandCreator';
import { SystemPriorities } from './systems/SystemPriorities';
import AttentionSystem from './systems/AttentionSystem';
import CommandSystem from './systems/CommandSystem';
import DisplaySystem from './systems/DisplaySystem';
import HotWordSystem from './systems/HotWordSystem';
import InterruptSystem from './systems/InterruptSystem';
import JiboTickProvider from './core/tick/JiboTickProvider';
import LookAtSystem from './systems/LookAtSystem';
import PlaySystem from './systems/PlaySystem';
import TakePhotoSystem from './systems/TakePhotoSystem';
import PhotoStreamSystem from './systems/PhotoStreamSystem';
import PersonStreamSystem from './systems/PersonStreamSystem';
import SetConfigSystem from './systems/SetConfigSystem';
import GetConfigSystem from './systems/GetConfigSystem';
import MotionStreamSystem from './systems/MotionStreamSystem';
import LoadAssetSystem from './systems/LoadAssetSystem';
import UnloadAssetSystem from './systems/UnloadAssetSystem';
import RemoteIndicatorSystem from './systems/RemoteIndicatorSystem';
import HeadTouchSystem from './systems/HeadTouchSystem';
import ScreenTouchSystem from './systems/ScreenTouchSystem';
import ListenSystem from './systems/ListenSystem';
import SessionSystem from './systems/SessionSystem';
import LightRingSystem from './systems/LightRingSystem';
import TestSystem from './systems/TestSystem';
import { RemoteIndicator, Attention, AssetCache, LightRing } from './components';
import { Permissions } from '../Permissions';
//
import { Log } from 'jibo-log';
import {AttentionMode} from 'jibo-command-protocol';

export enum Resource {
    LIGHT_RING = 'LIGHT_RING'
}

export class EntityManager
{
    public engine:Engine;
    public log:Log;
    private _permissions:Permissions;
    private _commandCreator: CommandCreator;
    private _tickProvider:JiboTickProvider;
    private _active:boolean = false;

    /**
     * Indicates if the engine has an active update loop.
     */
    public get active():boolean {
        return this._active;
    }

    constructor(permissions:Permissions)
    {
        this._permissions = permissions;
        this.prepare();
    }

    public prepare():void
    {
        this.engine = new Engine();
        this._commandCreator = new CommandCreator(this.engine, this._permissions);
    }

    public addSessionSystems(sessionEntity:Entity):void
    {
        // add default sytems
        this.engine.addSystem(new CommandSystem(), SystemPriorities.response);
        this.engine.addSystem(new InterruptSystem(), SystemPriorities.interrupt);
        this.engine.addSystem(new SessionSystem(), SystemPriorities.session);

        let useLightRing:boolean = false;

        if (this._permissions.test) {
            this.engine.addSystem(new TestSystem(), SystemPriorities.update);
        }

        if (this._permissions.play) {
            //speech, sound effects, probably playing animations through ESML
            this.engine.addSystem(new PlaySystem(), SystemPriorities.update);
        }
        if (this._permissions.display) {
            //screen display
            this.engine.addSystem(new DisplaySystem(), SystemPriorities.update);
        }
        if (this._permissions.lookAt) {
            //look at with body
            // NOTE :: To use the look at entity functionality you need lps permission
            this.engine.addSystem(new LookAtSystem(), SystemPriorities.update);
        }
        if (this._permissions.takePhoto) {
            //individual photos
            this.engine.addSystem(new TakePhotoSystem(), SystemPriorities.update);
        }
        if (this._permissions.video) {
            //photostream and video
            this.engine.addSystem(new PhotoStreamSystem(), SystemPriorities.update);
        }
        if (this._permissions.personStream) {
            //usage of LPS stream for person detection
            this.engine.addSystem(new PersonStreamSystem(), SystemPriorities.lps);
        }
        if (this._permissions.motionStream) {
            //usage of LPS stream for motion detection
            this.engine.addSystem(new MotionStreamSystem(), SystemPriorities.lps);
        }
        if (this._permissions.headTouch) {
            //usage of Head Touch stream
            this.engine.addSystem(new HeadTouchSystem(), SystemPriorities.update);
        }
        if (this._permissions.setConfig) {
            //usage of LPS stream
            this.engine.addSystem(new SetConfigSystem(), SystemPriorities.load);
        }
        if (this._permissions.getConfig) {
            //usage of LPS stream
            this.engine.addSystem(new GetConfigSystem(), SystemPriorities.update);
        }
        if (this._permissions.listen) {
            this.engine.addSystem(new ListenSystem(), SystemPriorities.update);
            useLightRing = true;
        }
        if (this._permissions.screenGesture) {
            this.engine.addSystem(new ScreenTouchSystem(), SystemPriorities.update);
        }
        // add system for HotWord subscription, if hot word permissions denied the system disables global listens
        this.engine.addSystem(new HotWordSystem(this._permissions.hotWord), SystemPriorities.update);
        if(this._permissions.hotWord) {
            useLightRing = true;
        }
        // add attention system, required whether we have permission or not
        this.engine.addSystem(new AttentionSystem(), SystemPriorities.lps);
        if (!this._permissions.attention) {
            // if no attention permissions set attention to OFF by default
            // NOTE :: Permissions may get more nuanced around default attention mode
            let attention:Attention = new Attention();
            attention.mode = AttentionMode.Off;
            // add component to entity responsible for handles remote mode
            sessionEntity.add(attention);
        }
        if (this._permissions.fetchAsset) {
            this.engine.addSystem(new LoadAssetSystem(), SystemPriorities.load);
            this.engine.addSystem(new UnloadAssetSystem(), SystemPriorities.load);
            let assetCache:Entity = new Entity('assetCache');
            assetCache.add(new AssetCache());
            this.engine.addEntity(assetCache);
        }

        // remote mode specifics
        if (this._permissions.hideRemoteIndicator) {
            //if allowed to hide Remote Mode indicators then don't add RemoteIndicator component
        } else {
            this.engine.addSystem(new RemoteIndicatorSystem(), SystemPriorities.update);
            // add component to manage remote mode visualization
            sessionEntity.add(new RemoteIndicator());
            // add component for light ring usage
            sessionEntity.add(new LightRing());
            useLightRing = true;
        }

        // check if light ring control is needed
        if(useLightRing) {
            this.engine.addSystem(new LightRingSystem(), SystemPriorities.light);
        }
    }

    public addCommand(data:JIBO.v1.Command):Entity
    {
        let entity:Entity = this._commandCreator.commandFromRequestProtocol(data);
        this.engine.addEntity(entity);
        return entity;
    }

    public start():void
    {
        this._active = true;
        if(!this._tickProvider )
        {
            this._tickProvider = new JiboTickProvider();
            this._tickProvider.add( delta => this.engine.update( delta ) );
        }
        this._tickProvider.start();
        // on start force an update, allows first update results to be synchronous
        this.engine.update(0);
    }

    public stop():void
    {
        this._active = false;
        this._tickProvider.stop();
    }

    public reset():void
    {
        // stop update loop
        this.stop();
        this._tickProvider.removeAll();
        this.engine.updateComplete.removeAll();
        // NOTE :: remove entities first, so systems have change to call remove methods
        this.engine.removeAllEntities();
        this.engine.removeAllSystems();

        // TODO :: May want more clean up here, releasing node lists dictionary for example
    }

    public dispose():void
    {
        this.reset();
        this.engine = null;
        this._tickProvider = null;
    }
}
