import { MessageOut } from '../../CommandConnector';
import { DisconnectMethod } from '../../CommandSessionManager';

export class Session
{
    // CAN SET EXTERNALLY
    // unique session identifier
    public id:string;
    // max time in seconds for reconnection to happen
    public reconnectTimeout:number;
    // maximum time in seconds of inactivity before ending session
    public inactivityTimeout:number;

    // FOR SYSTEM USE
    // waiting for reconnection
    public waitingOnReconnect:boolean = false;
    // flag set when a session is able to reconnect
    public reconnection:boolean = false;
    // seconds spent waiting for reconnection
    public reconnectDuration:number = 0;
    // seconds of inactivity
    public inactivityDuration:number = 0;
    // callback for sending messages back to requester
    public sendMethod:MessageOut;
    // callback for session close
    public endSessionMethod:DisconnectMethod;
    // stores events that cannont be sent due to connection loss
    public storedEvents:JIBO.v1.AllResponses[];
    // seconds to wait on head touch to exit
    public headTouchStopTime:number;

    // flag to determine if session has an active conection
    private _hasConnection:boolean = true;
    public get hasConnection():boolean {
        return this._hasConnection;
    }
    public set hasConnection(connected:boolean) {
        this._hasConnection = connected;
        if(connected){
            if(this.waitingOnReconnect) {
                this.reconnection = true;
            }
            this.waitingOnReconnect = false;
            this.reconnectDuration = 0;
        }
        else {
            if(!this.waitingOnReconnect) {
                this.waitingOnReconnect = true;
            }
        }
    }

    constructor(id?:string, sendMethod?:MessageOut, reconnectTimeout:number = 1000, inactivityTimeout:number = 0) {
        this.storedEvents = [];
        if(id) {
            this.id = id;
        }
        if(sendMethod) {
            this.sendMethod = sendMethod;
        }
        if(reconnectTimeout) {
            this.reconnectTimeout = reconnectTimeout;
        }
        if(inactivityTimeout) {
            this.inactivityTimeout = inactivityTimeout;
        }
    }

}
