import { NodeList, System, Engine } from '../core';
import { jiboRef } from '../../jibo';
import { ListenNode } from '../nodes';
import { Listen } from '../components';
import { RequestCommand } from '../components/RequestCommand';
import CommandUtil from '../../CommandUtil';
import { AsyncCommandEvent, ResponseCode, ListenEvents, ListenStopReasons } from 'jibo-command-protocol';
//Typings only import: do not use for actual code
import JiboType = require('../../../../jibo');

export default class ListenSystem extends System
{
    private nodes:NodeList<ListenNode>;

    constructor()
    {
        super();
    }

    public addToEngine( engine:Engine ):void
    {
        this.nodes = engine.getNodeList( ListenNode );
        this.nodes.nodeRemoved.add( this.onRemoved );
    }

    public update( time:number ):void
    {
        // there can only be one listen at a time, the last listen request takes priority
        let node:ListenNode = this.nodes.head;
        for( node; node; node = node.next )
        {
            let request:RequestCommand = node.request;
            if(node.next) {
                // interrupt
                if (request.acknowledged) {
                    let response: JIBO.v1.AsyncErrorEvent = {
                        Event: AsyncCommandEvent.Error,
                        EventError: {
                            ErrorString: "Listen overwritten",
                            ErrorCode: 1
                        }
                    };
                    request.addResponse(response,true);
                } else {
                    request.setAcknowledge(ResponseCode.Conflict,true);
                }
            }
            else {
                let listen:Listen = node.listen;
                if (!listen.mim){
                    this.createMim(listen);
                    listen.isActive = true;
                    // set light ring color
                    node.lightRing.setColor(CommandUtil.LISTEN_COLORS);
                    //TODO Implement MaxSpeechTimeout
                } else {
                    let status : JiboType.bt.Status = listen.mim.update();
                    if (status !== jiboRef.jibo.bt.Status.IN_PROGRESS){
                        // Determine if the MIM was interrupted
                        if (status === jiboRef.jibo.bt.Status.INTERRUPTED){
                            let response: JIBO.v1.ListenStopEvent = {
                                Event: AsyncCommandEvent.Stop,
                                StopReason: ListenStopReasons.Interrupted,
                            };
                            request.addResponse(response, true);
                        } else { // The MIM ended OK, so we have 3 options
                            // We are sending null text from the component if 'NoInput'
                            if (node.listen.speech === null){
                                let response: JIBO.v1.ListenStopEvent = {
                                    Event: AsyncCommandEvent.Stop,
                                    StopReason: ListenStopReasons.NoInput,
                                };
                                request.addResponse(response, true);
                            } else { // We have a result; but it might be empty if 'NoMatch'
                                if (node.listen.speech.text === ""){
                                    let response: JIBO.v1.ListenStopEvent = {
                                        Event: AsyncCommandEvent.Stop,
                                        StopReason: ListenStopReasons.NoMatch,
                                    };
                                    request.addResponse(response, true);
                                } else {
                                    let response: JIBO.v1.ListenResultEvent = {
                                        Event : ListenEvents.ListenResult,
                                        LanguageCode : "en-US",
                                        Speech : listen.speech.text
                                    };
                                    request.addResponse(response, true);
                                }
                            }
                        }
                        listen.isActive = false;
                    }
                }
            }
        }
    }

    public removeFromEngine( engine:Engine ):void
    {
        this.nodes = null;
    }

    private createMim( listen:Listen ):void
    {
        let mimConfig = {
            mim_id: "Listen System",
            mim_type: "optional-response",
            rule_name: "shared/wildcard",
            timeout: listen.maxNoSpeechTimeout,
            barge_in: false,
            prompts: [
                {
                    prompt_category: "Entry-Core",
                    prompt_sub_category: "AN",
                    index: 1,
                    condition: "",
                    prompt: "", //TODO This could allow us to implement questions
                    media: "silence",
                    prompt_id: ""
                }
            ],
            num_tries_for_gui: 0,
            es_auto_tagging: true,
            ignore_no_match: true
            };

        let mimOptions = {
            onSuccess: listen.onMimEnd.bind(listen),
            mimConfig: mimConfig,
            assetPack: "jibo",
            onFailure: listen.onMimEnd.bind(listen),
            onPositionalSelect: null,
            mimPath: null,
            guiConfig: null,
            getPromptData: null,
            asrMetadata: {
                skill: "remote"
            },
            isMenu: false
        };

        listen.mim = new jiboRef.jibo.bt.behaviors.Mim(mimOptions);
        listen.mim.start();
    }

    private onRemoved = ( node:ListenNode ) => {
        if(node.listen.isActive ){
            if (node.listen.mim) {
                node.listen.mim.stopAndDestroy();
                node.listen.mim = null;
            }
            node.listen.isActive = false;
        }
    }
}
