import { Engine, NodeList, System } from '../core';
import { RemoteIndicatorNode } from '../nodes';
import { RemoteIndicator } from '../components';
import { jiboRef } from '../../jibo';

export default class RemoteIndicatorSystem extends System
{
    private nodes:NodeList<RemoteIndicatorNode>;

    constructor()
    {
        super();
    }

    public addToEngine( engine:Engine ):void
    {
        this.nodes = engine.getNodeList( RemoteIndicatorNode );

        for( let node:RemoteIndicatorNode = this.nodes.head; node; node = node.next )
        {
            this.onAdded( node );
        }
        this.nodes.nodeAdded.add( this.onAdded );
        this.nodes.nodeRemoved.add( this.onRemoved );
    }

    public update( time:number ):void
    {
        // only processes first node
        let node:RemoteIndicatorNode = this.nodes.head;
        if(node) {
            let indicator:RemoteIndicator = node.indicator;
            // if duration reached flip direction
            if(indicator.lerpIsRising) {
                indicator.timer += time;
                if (indicator.timer >= indicator.duration) {
                    indicator.timer = indicator.duration;
                    indicator.lerpIsRising = !indicator.lerpIsRising;
                }
            }
            else {
                indicator.timer -= time;
                if (indicator.timer <= 0) {
                    indicator.timer = 0;
                    indicator.lerpIsRising = !indicator.lerpIsRising;
                }
            }
            //calculate interpolation
            const lerpVal = Math.sin(indicator.timer / indicator.duration); // sin wave
            //uodate light ring color
            node.lightRing.setColors(
                indicator.minLEDColor[0] + (lerpVal * indicator.deltaInColor[0]),
                indicator.minLEDColor[1] + (lerpVal * indicator.deltaInColor[1]),
                indicator.minLEDColor[2] + (lerpVal * indicator.deltaInColor[2])
            );

            // fade icon alpha: We add the minimum value to a sinus wave
            // whose amplitude is the difference betwwen the max-min alpha
            indicator.icon.alpha = indicator.minAlpha +
                                   (lerpVal*(indicator.deltaAlpha));
        }
    }

    public removeFromEngine( engine:Engine ):void
    {
        this.nodes = null;
    }

    private onAdded = ( node:RemoteIndicatorNode ) => {
        let indicator:RemoteIndicator = node.indicator;
        // create maximum and minimum colors
        indicator.maxLEDColor = this.hexToLightRing(indicator.maxHexColor);
        indicator.minLEDColor = this.hexToLightRing(indicator.minHexColor);

        // calculate the delta only once, in a general way
        indicator.deltaInColor[0] = indicator.maxLEDColor[0] - indicator.minLEDColor[0];
        indicator.deltaInColor[1] = indicator.maxLEDColor[1] - indicator.minLEDColor[1];
        indicator.deltaInColor[2] = indicator.maxLEDColor[2] - indicator.minLEDColor[2];
        indicator.deltaAlpha = indicator.maxAlpha - indicator.minAlpha;
        // create icon
        let graphic:PIXI.Graphics = new PIXI.Graphics();
        graphic.beginFill(parseInt(indicator.dotColor));
        graphic.drawCircle(0,0, indicator.dotRadius);
        let icon:PIXI.Container = new PIXI.Container();

        // start full color
        icon.alpha = indicator.maxAlpha;
        indicator.timer = indicator.duration;
        indicator.lerpIsRising = true;

        icon.x = jiboRef.jibo.face.width - indicator.horizontalOffset;
        icon.y = jiboRef.jibo.face.height - indicator.verticalOffset;
        icon.addChild(graphic);
        // add icon to display
        jiboRef.jibo.face.views.addWatermark(icon);
        // give component reference
        node.indicator.icon = icon;
    }

    private onRemoved = ( node:RemoteIndicatorNode ) => {
        // remove icon from display
        if(node.indicator.icon) {
            jiboRef.jibo.face.views.removeWatermark();
        }
    }

    private hexToLightRing(hex:string) : [number, number, number] {
        let hexNum:string[] = /0x([0-9a-f]{2})([0-9a-f]{2})([0-9a-f]{2})/i.exec(hex);
        return [parseInt(hexNum[1],16)/255, parseInt(hexNum[2],16)/255, parseInt(hexNum[3],16)/255];
    }
}
