// Only importing type definition - do not use for runtime things
import JiboImport = require('../../jibo');

let _jibo:typeof JiboImport;
//provides a single entry point for jibo module to be used for runtime purposes - has to be a static
//class to allow for a getter
export class jiboRef {

    public static get jibo() {
        return _jibo;
    }
}

//export a namespace that is merged with the static class - this should allow code to be
/*
import {jiboRef} from './jibo.ts';

const flow:jiboRef.jibo.flow.FlowExecutor = jiboRef.jibo.flow.run(...);
*/
export namespace jiboRef {
    /**
     * @private
     */
    export function setJibo(value:typeof JiboImport) {
        _jibo = value;
    }
}
