import { NodeList, System, Engine } from '../core';
import { jiboRef } from '../../jibo';
import { RequestCommand } from '../components/RequestCommand';
import { MotionStreamNode } from '../nodes';

import {ResponseCode, MotionEvents } from 'jibo-command-protocol';

export default class MotionStreamSystem extends System
{
    private nodes:NodeList<MotionStreamNode>;
    private engine:Engine;
    private detectedMotions: JIBO.v1.MotionEntity[] = [];

    constructor()
    {
        super();
    }

    public addToEngine( engine:Engine ):void
    {
        this.engine = engine;
        this.nodes = this.engine.getNodeList( MotionStreamNode );
    }

    public removeFromEngine( engine:Engine ):void
    {
        this.nodes = null;
        this.detectedMotions = null;
    }

    public update( time:number ):void
    {
        // Last inserted node gets priority
        let node:MotionStreamNode = this.nodes.tail;
        if(node)
        {
            let request:RequestCommand = node.request;

            this.detectMotion();
            if (this.detectedMotions.length > 0)
            {
                let response: JIBO.v1.MotionEvent = {
                    Event: MotionEvents.MotionDetected,
                    Motions: this.detectedMotions
                };
                request.addResponse(response, false);
            }
            //go and mark any other nodes as busy
            for (node = node.previous; node; node = node.previous)
            {
                node.request.setAcknowledge(ResponseCode.Conflict, true);
            }
        }
    }

    private detectMotion(): void
    {
        let lpsData:any = jiboRef.jibo.lps.motionData;
        this.detectedMotions.length = 0;
        let detectedMotion: JIBO.v1.MotionEntity = {
            Intensity: null,
            WorldCoords: null,
            ScreenCoords: null
        };
        for (let entity of lpsData.entities)
        {
            if (entity.description = "motion")
            {
                detectedMotion.Intensity = entity.intensity;
                detectedMotion.WorldCoords = [entity.position.x, entity.position.y, entity.position.z];
                if (entity.parts.length > 0){
                    if (entity.parts[0].value.trackers.length > 0){
                        let rectangle:any = entity.parts[0].value.trackers[0].rectangle;
                        let x: number = rectangle.left;
                        let y: number = rectangle.top;
                        let width: number = rectangle.right-rectangle.left;
                        let height: number = rectangle.bottom-rectangle.top;
                        detectedMotion.ScreenCoords = [x, y, width, height];
                        this.detectedMotions.push(detectedMotion);                        
                    }
                }
            }
        }
    }
}
