import {ResponseCode} from 'jibo-command-protocol';

export class RequestCommand
{
    // id of command
    public id:string;

    // version of protocol
    public version:JIBO.v1.ProtocolVersions.ProtocolVersionType;

    // flag for whether acknowledgement was sent
    public acknowledged:boolean = false;

    // acknowledgement code, default to Accepted
    private _acknowledgeCode:JIBO.v1.ResponseCodes.ResponseCodeType = ResponseCode.Accepted;
    public get acknowledgeCode():JIBO.v1.ResponseCodes.ResponseCodeType
    {
        return this._acknowledgeCode;
    }
    // acknowledgement body (where applicable)
    private _acknowledgeData:any|string;
    public get acknowledgeData():any|string
    {
        return this._acknowledgeData;
    }

    private _isDirty:boolean = true;
    // array of response data
    private _responses:any[];
    // when true will message final message and delete entity
    private _complete:boolean = false;
    public get complete():boolean {
        return this._complete;
    }

    public get isDirty():boolean
    {
        return this._isDirty;
    }

    public get responses():any[]
    {
        return this._responses;
    }

    constructor(data?:JIBO.v1.Command)
    {
        this._responses = [];
        if(data)
        {
            this.applyData(data);
        }
    }

    public applyData(data:JIBO.v1.Command):void
    {
        //this.header = data;
        this.id = data.ClientHeader.TransactionID;
    }

    /**
     * Set acknowledgement code, set dirty flag true
     */
    public setAcknowledge(code:JIBO.v1.ResponseCodes.ResponseCodeType, isComplete:boolean = false, data?:any|string):void
    {
        this._acknowledgeCode = code;
        this._isDirty = true;
        if(isComplete) {
            this._complete = true;
        }
        if(data) {
            this._acknowledgeData = data;
        }
    }

    /**
     * Add response, set dirty flag true
     */
    public addResponse(data:any, isComplete:boolean = false):void
    {
        this._responses.push(data);
        this._isDirty = true;
        if(isComplete) {
            this._complete = true;
        }
    }

    /**
     * Set complete flag to true, set dirty flag true
     */
    public setComplete():void
    {
        this._isDirty = true;
        this._complete = true;
    }

    public clean():void
    {
        this._isDirty = false;
        this._responses.length = 0;
    }

}
