import uuid = require('uuid');
import { Log } from 'jibo-log';
import parentLog from './log';
import CommandManager from './commander/CommandManager';
import CommandSession from './CommandSession';
import CommandUtil from './CommandUtil';
import { MessageOut } from './CommandConnector';
import  { Permissions } from './Permissions';
import { CommandTypes } from 'jibo-command-protocol';

export type DisconnectMethod = (code:number) => void;

export default class CommandSessionManager {
    private log: Log;
    // current permissions, derived from ACO, persist for duration of session
    private _permissions:Permissions;
    // currently active commandSession
    private _commandSession: CommandSession;
    // stores pending session command until we can start session
    private _pendingSessionCommand: JIBO.v1.Command;

    public set permissions(permissions:Permissions) {
        this._permissions = permissions;
    }

    public get version():JIBO.v1.ProtocolVersions.ProtocolVersionType {
        if(this._permissions) {
            return this._permissions.version;
        }
        return null;
    }

    public get session():CommandSession {
        return this._commandSession;
    }

    public get sessionId():string {
        if(this._commandSession) {
            return this._commandSession.sessionId;
        }
        this.log.warn('no active command session, cannot retrieve a sessionId');
        return '';
    }

    constructor() {
        this._commandSession = null;
        this._permissions = null;
        this._pendingSessionCommand = null;
        this.log = parentLog.createChild('session-manager');
    }


    /**
     * Check if command's session id does not match with active session
     * @param {string} sessionId 
     */
    public checkSessionMismatch(sessionId:string):boolean {
        if(this._commandSession) {
            return (sessionId !== this._commandSession.session.id);
        }
        return false;
    }

    /**
     * Intercept and handle StartSession commands, because they are more of a pain to do with the component system
     * @param data 
     */
    public checkSessionCommand(data:JIBO.v1.Command):boolean {
        if (CommandUtil.getCommandType(data, this.version) === CommandTypes.StartSession) {
            this._pendingSessionCommand = data;
            return true;
        }
        return false;
    }

    //
    /**
     * Reconnect an existing session or create a new one.
     * New sessions rely on the pending session command supplied by checkSessionCommand
     */
    public startSession(sendMethod:MessageOut, sessionCloseMethod:DisconnectMethod):void {
        // if there was a previous session, restore
        if (this._commandSession) {
            // TODO :: Need we need to send a reconnection event, if we had a disconnection
            this._commandSession.session.hasConnection = true;
            this.log.info('startSession : session has been restored');
        }
        else {
            this.log.info('startSession : creating a new session');
            // create new command session
            const commander:CommandManager = new CommandManager(this._permissions);
            const sessionEntity = commander.onCommand(this._pendingSessionCommand);
            // set session id, if a session id was provided with command request use that, otherwise create a unique one
            let sessionId:string = CommandUtil.getSessionId(this._pendingSessionCommand, this._permissions.version) || uuid.v4();
            this._commandSession = new CommandSession(commander, sessionEntity, sessionId);
            // assign callbacks to Session component
            this._commandSession.session.sendMethod = sendMethod;
            this._commandSession.session.endSessionMethod = sessionCloseMethod;
            // start the entity engine
            commander.startSession(sessionEntity);
        }
    }

    // End the current session
    // This means disposing of the current instance of the command manager.
    public endSession():void {
        if(this._commandSession) {
            // TODO :: Disposing should probably be async, so systems have time to clean up
            this._commandSession.dispose();
            this._commandSession = null;
        }
        else {
            this.log.info('endSession : command session is already null, nothing to dispose');
        }
    }

    public resetInactivityTimeout():void {
        if(this._commandSession) {
            this._commandSession.session.inactivityDuration = 0;
        }
    }

    public resetReconnectTimeout():void {
        if(this._commandSession) {
            this._commandSession.session.reconnectDuration = 0;
        }
    }

    public startCommand(data:JIBO.v1.Command):void {
        this._commandSession.commandManager.onCommand(data);
    }

    public handleFailedResponse(message:JIBO.v1.AllResponses):boolean {
        if(this._commandSession){
            this._commandSession.storeFailedResponse(message);
            return true;
        }
        return false;
    }

    /**
     * Called in case of disconnection, determines if a session restore is possible
     */
    public handleDisconnection():boolean {
        // Bail if there is no session
        if(!this._commandSession) {
            // no session to reconnect
            return false;
        }
        // flag lack of connection on session
        this._commandSession.session.hasConnection = false;
        return true;
    }

}
