
export class TakePhoto
{
    public isActive:boolean = false;
    public assetUrl:string = null;
    public distortion:boolean = false;
    public camera:JIBO.v1.Cameras.CameraType;
    public resolution:JIBO.v1.CameraResolutions.CameraResolutionType;

    constructor(distortion:boolean, camera:JIBO.v1.Cameras.CameraType, resolution:JIBO.v1.CameraResolutions.CameraResolutionType)
    {
        this.assetUrl = null;
        this.distortion = distortion;
        this.camera = camera;
        this.resolution = resolution;
    }
}
