import { Engine, NodeList, System } from '../core';
import { AttentionNode } from '../nodes';
import { Attention } from '../components';
import { jiboRef } from '../../jibo';
import { AsyncCommandEvent, ResponseCode } from 'jibo-command-protocol';
//Typings only import: do not use for actual code
import JiboType = require('../../../../jibo');

/**
 * AttentionSystem pushes attention modes to the expression service.
 * This system works to maintain that only one mode is pushed at a time.
 * When all AttentionNodes are removed the attention mode will return the underlying mode.
 */
export default class AttentionSystem extends System
{
    private nodes:NodeList<AttentionNode>;

    constructor()
    {
        super();
    }

    public addToEngine( engine:Engine ):void
    {
        this.nodes = engine.getNodeList( AttentionNode );
        this.nodes.nodeRemoved.add( this.onRemoved );
    }

    public update( time:number ):void
    {
        let node:AttentionNode = this.nodes.head;
        for( node; node; node = node.next )
        {
            // activate latest node, release and end older ones
            if(node.next) {
                this.releaseAttention(node.attention);
                if(node.request) {
                    if(node.request.acknowledged) {
                        let response: JIBO.v1.AsyncErrorEvent = {
                            Event: AsyncCommandEvent.Error,
                            EventError: {
                                ErrorString: "Attention mode overwritten",
                                ErrorCode: 1
                            }
                        };
                        node.request.addResponse(response,true);
                    }
                    else {
                        node.request.setAcknowledge( ResponseCode.Conflict, true );
                    }
                }
            }
            // tail node should be made active
            else if(!node.attention.active)
            {
                let attention = node.attention;
                attention.active = true;
                // set attention mode
                jiboRef.jibo.expression.pushAttentionMode(this.convertMode(attention.mode))
                .then ((handle) => {
                    // if attention mode is still active (attention component has not been removed) store handle
                    if(attention.active) {
                        attention.handle = handle;
                    }
                    // otherwise release handle, since Attention component has been removed
                    else {
                        handle.release()
                        .then(() => {
                            // no opt
                        });
                    }
                });

                // if component has request create response
                if(node.request) {
                    node.request.setAcknowledge(ResponseCode.Created, true);
                }
            }
        }
    }

    public removeFromEngine( engine:Engine ):void
    {
        this.nodes = null;
    }

    private onRemoved = ( node:AttentionNode ) => {
        this.releaseAttention(node.attention);
    }

    private convertMode(mode:JIBO.v1.AttentionModes.AttentionModeType):JiboType.expression.AttentionMode {
        return (<JiboType.expression.AttentionMode>String(mode));
    }

    private releaseAttention(attention:Attention):void {
        if(attention.active) {
            attention.active = false;
            if(attention.handle) {
                attention.handle.release()
                .then(() => {
                    attention.handle = null;
                });
            }
        }
    }
}
